import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Param,
  Body,
  UseGuards,
  HttpCode,
  HttpStatus,
} from '@nestjs/common';
import {
  ApiBearerAuth,
  ApiOperation,
  ApiParam,
  ApiResponse,
  ApiTags,
} from '@nestjs/swagger';
import { ArbiConfigsService } from './arbi-configs.service';
import { CreateArbiConfigDto, UpdateArbiConfigDto } from './dto/arbi-config.dto';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';
import { User } from '../users/entities/user.entity';
import { PricesService } from '../prices/prices.service';

@ApiTags('ArbiConfigs')
@ApiBearerAuth()
@UseGuards(JwtAuthGuard)
@Controller('arbi-configs')
export class ArbiConfigsController {
  constructor(
    private readonly service: ArbiConfigsService,
    private readonly pricesService: PricesService,
  ) {}

  @Get()
  @ApiOperation({
    summary: 'Список арбитражных конфигов',
    description:
      'Возвращает все арбитражные конфиги текущего пользователя с подгруженными источниками.',
  })
  @ApiResponse({ status: 200, description: 'Массив конфигов' })
  findAll(@CurrentUser() user: User) {
    return this.service.findAll(user.id);
  }

  @Get(':id')
  @ApiOperation({
    summary: 'Детали арбитражного конфига',
    description:
      'Возвращает конфиг по ID с подгруженными референсными и торговой подписками.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiResponse({ status: 200, description: 'Конфиг' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  findOne(@CurrentUser() user: User, @Param('id') id: string) {
    return this.service.findOne(user.id, id);
  }

  @Post()
  @ApiOperation({
    summary: 'Создать арбитражный конфиг',
    description:
      'Создаёт новый конфиг из подписок пользователя. Указываются референсные источники ' +
      '(для расчёта средней цены), торговый источник (DEX для исполнения), ' +
      'актив прибыли и проскальзывание.',
  })
  @ApiResponse({ status: 201, description: 'Конфиг создан' })
  @ApiResponse({ status: 400, description: 'Некорректные данные или подписки не принадлежат пользователю' })
  create(@CurrentUser() user: User, @Body() dto: CreateArbiConfigDto) {
    return this.service.create(user.id, dto);
  }

  @Patch(':id')
  @ApiOperation({
    summary: 'Обновить арбитражный конфиг',
    description: 'Обновляет поля конфига. Можно передавать только изменённые поля.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiResponse({ status: 200, description: 'Конфиг обновлён' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  update(
    @CurrentUser() user: User,
    @Param('id') id: string,
    @Body() dto: UpdateArbiConfigDto,
  ) {
    return this.service.update(user.id, id, dto);
  }

  @Delete(':id')
  @HttpCode(HttpStatus.NO_CONTENT)
  @ApiOperation({
    summary: 'Удалить арбитражный конфиг',
    description: 'Удаляет конфиг по ID. Пользователь может удалять только свои конфиги.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiResponse({ status: 204, description: 'Конфиг удалён' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  remove(@CurrentUser() user: User, @Param('id') id: string) {
    return this.service.remove(user.id, id);
  }

  @Get(':id/prices')
  @ApiOperation({
    summary: 'Ценовые данные всех подписок конфига',
    description:
      'Загружает исторические bid/ask данные для каждой подписки конфига ' +
      '(все референсные + торговая). Используется для графика на странице конфига.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiResponse({ status: 200, description: 'Объект с ценовыми данными по каждой подписке' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  async getPrices(@CurrentUser() user: User, @Param('id') id: string) {
    const { tradingSubscriptionId, referenceSubscriptionIds, allSubscriptionIds } =
      await this.service.getSubscriptionIds(user.id, id);

    const priceResults: Record<string, any> = {};
    for (const subId of allSubscriptionIds) {
      try {
        priceResults[subId] = await this.pricesService.getPricesBySubscription(
          subId,
          user.id,
        );
      } catch {
        priceResults[subId] = { series: [], data: [] };
      }
    }

    return {
      tradingSubscriptionId,
      referenceSubscriptionIds,
      prices: priceResults,
    };
  }
}

import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Param,
  Body,
  Query,
  UseGuards,
  HttpCode,
  HttpStatus,
} from '@nestjs/common';
import {
  ApiBearerAuth,
  ApiOperation,
  ApiParam,
  ApiQuery,
  ApiResponse,
  ApiTags,
} from '@nestjs/swagger';
import { ArbiConfigsService } from './arbi-configs.service';
import { CreateArbiConfigDto, UpdateArbiConfigDto } from './dto/arbi-config.dto';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';
import { User } from '../users/entities/user.entity';
import { PricesService } from '../prices/prices.service';

@ApiTags('ArbiConfigs')
@ApiBearerAuth()
@UseGuards(JwtAuthGuard)
@Controller('arbi-configs')
export class ArbiConfigsController {
  constructor(
    private readonly service: ArbiConfigsService,
    private readonly pricesService: PricesService,
  ) {}

  @Get()
  @ApiOperation({
    summary: 'Список арбитражных конфигов',
    description:
      'Возвращает все арбитражные конфиги текущего пользователя с подгруженными источниками.',
  })
  @ApiResponse({ status: 200, description: 'Массив конфигов' })
  findAll(@CurrentUser() user: User) {
    return this.service.findAll(user.id);
  }

  @Get(':id')
  @ApiOperation({
    summary: 'Детали арбитражного конфига',
    description:
      'Возвращает конфиг по ID с подгруженными референсными и торговой подписками.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiResponse({ status: 200, description: 'Конфиг' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  findOne(@CurrentUser() user: User, @Param('id') id: string) {
    return this.service.findOne(user.id, id);
  }

  @Post()
  @ApiOperation({
    summary: 'Создать арбитражный конфиг',
    description:
      'Создаёт новый конфиг из подписок пользователя. Указываются референсные источники ' +
      '(для расчёта средней цены), торговый источник (DEX для исполнения), ' +
      'актив прибыли и проскальзывание.',
  })
  @ApiResponse({ status: 201, description: 'Конфиг создан' })
  @ApiResponse({ status: 400, description: 'Некорректные данные или подписки не принадлежат пользователю' })
  create(@CurrentUser() user: User, @Body() dto: CreateArbiConfigDto) {
    return this.service.create(user.id, dto);
  }

  @Patch(':id')
  @ApiOperation({
    summary: 'Обновить арбитражный конфиг',
    description: 'Обновляет поля конфига. Можно передавать только изменённые поля.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiResponse({ status: 200, description: 'Конфиг обновлён' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  update(
    @CurrentUser() user: User,
    @Param('id') id: string,
    @Body() dto: UpdateArbiConfigDto,
  ) {
    return this.service.update(user.id, id, dto);
  }

  @Delete(':id')
  @HttpCode(HttpStatus.NO_CONTENT)
  @ApiOperation({
    summary: 'Удалить арбитражный конфиг',
    description: 'Удаляет конфиг по ID. Пользователь может удалять только свои конфиги.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiResponse({ status: 204, description: 'Конфиг удалён' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  remove(@CurrentUser() user: User, @Param('id') id: string) {
    return this.service.remove(user.id, id);
  }

  @Get(':id/prices')
  @ApiOperation({
    summary: 'Ценовые данные всех подписок конфига',
    description:
      'Загружает исторические bid/ask данные для каждой подписки конфига ' +
      '(все референсные + торговая). Данные кэшируются на 1 час. ' +
      'Для принудительного обновления передайте noCache=true.',
  })
  @ApiParam({ name: 'id', description: 'UUID конфига' })
  @ApiQuery({ name: 'noCache', required: false, type: Boolean, description: 'Игнорировать кэш и обновить данные' })
  @ApiResponse({ status: 200, description: 'Объект с ценовыми данными по каждой подписке' })
  @ApiResponse({ status: 404, description: 'Конфиг не найден' })
  async getPrices(
    @CurrentUser() user: User,
    @Param('id') id: string,
    @Query('noCache') noCache?: string,
  ) {
    const { tradingSubscriptionId, referenceSubscriptionIds, allSubscriptionIds } =
      await this.service.getSubscriptionIds(user.id, id);

    const forceFresh = noCache === 'true';
    const priceResults: Record<string, any> = {};
    for (const subId of allSubscriptionIds) {
      try {
        priceResults[subId] = await this.pricesService.getPricesBySubscription(
          subId,
          user.id,
          forceFresh,
        );
      } catch {
        priceResults[subId] = { series: [], data: [] };
      }
    }

    return {
      tradingSubscriptionId,
      referenceSubscriptionIds,
      prices: priceResults,
    };
  }
}

import { Controller, Get, Param, UseGuards } from '@nestjs/common';
import { ApiBearerAuth, ApiOperation, ApiParam, ApiResponse, ApiTags } from '@nestjs/swagger';
import { PricesService } from './prices.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';
import { User } from '../users/entities/user.entity';

@ApiTags('Prices')
@ApiBearerAuth()
@UseGuards(JwtAuthGuard)
@Controller('prices')
export class PricesController {
  constructor(private readonly service: PricesService) {}

  @Get('subscription/:subscriptionId')
  @ApiOperation({
    summary: 'Ценовые данные по подписке',
    description:
      'Возвращает историю цен (bid/ask) для указанной подписки. ' +
      'Данные запрашиваются из arbiDexServerBots на основе маппинга sourceId+pairId → PriceStore keys.',
  })
  @ApiParam({ name: 'subscriptionId', description: 'UUID подписки' })
  @ApiResponse({ status: 200, description: 'Объект с массивом серий и массивом ценовых точек' })
  @ApiResponse({ status: 400, description: 'Маппинг не найден или сервер котировок недоступен' })
  @ApiResponse({ status: 404, description: 'Подписка не найдена' })
  getPricesBySubscription(
    @CurrentUser() user: User,
    @Param('subscriptionId') subscriptionId: string,
  ) {
    return this.service.getPricesBySubscription(subscriptionId, user.id);
  }
}

import { Controller, Get, Param, Query, UseGuards } from '@nestjs/common';
import { ApiBearerAuth, ApiOperation, ApiParam, ApiQuery, ApiResponse, ApiTags } from '@nestjs/swagger';
import { PricesService } from './prices.service';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';
import { User } from '../users/entities/user.entity';

@ApiTags('Prices')
@ApiBearerAuth()
@UseGuards(JwtAuthGuard)
@Controller('prices')
export class PricesController {
  constructor(private readonly service: PricesService) {}

  @Get('subscription/:subscriptionId')
  @ApiOperation({
    summary: 'Ценовые данные по подписке',
    description:
      'Возвращает историю цен (bid/ask) для указанной подписки. ' +
      'Данные кэшируются на 1 час. Для принудительного обновления передайте noCache=true.',
  })
  @ApiParam({ name: 'subscriptionId', description: 'UUID подписки' })
  @ApiQuery({ name: 'noCache', required: false, type: Boolean, description: 'Игнорировать кэш и обновить данные' })
  @ApiResponse({ status: 200, description: 'Объект с массивом серий и массивом ценовых точек' })
  @ApiResponse({ status: 400, description: 'Маппинг не найден или сервер котировок недоступен' })
  @ApiResponse({ status: 404, description: 'Подписка не найдена' })
  getPricesBySubscription(
    @CurrentUser() user: User,
    @Param('subscriptionId') subscriptionId: string,
    @Query('noCache') noCache?: string,
  ) {
    return this.service.getPricesBySubscription(subscriptionId, user.id, noCache === 'true');
  }
}

import { Injectable, NotFoundException, BadRequestException, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { buildStoreKeys, detectKeyFormat, SOURCE_META } from './market-data-keys';

/** Точка из PriceStore arbiDexServerBots */
interface BotsPricePoint {
  t: number; // timestamp ms
  v: number; // value
}

/** Ответ от /prices/keys (POST) — каждый ключ содержит объект с полем points */
interface BotsPriceKeyData {
  points: BotsPricePoint[];
  count?: number;
  last?: BotsPricePoint;
}

interface BotsPriceKeysResponse {
  [key: string]: BotsPriceKeyData;
}

/** Конфиг серии для фронтенда */
export interface PriceSeriesConfig {
  key: string;
  name: string;
  color: string;
}

/** Точка данных для фронтенда */
export interface ChartPricePoint {
  time: number;
  [field: string]: number;
}

/** Полный ответ для фронтенда */
export interface SubscriptionPriceData {
  series: PriceSeriesConfig[];
  data: ChartPricePoint[];
}

@Injectable()
export class PricesService {
  private readonly logger = new Logger(PricesService.name);
  private readonly marketDataUrl: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl = this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить ценовые данные по subscriptionId.
   * Маппит sourceId+pairId → ключи PriceStore, запрашивает историю из arbiDexServerBots,
   * трансформирует в формат PriceChartComponent.
   */
  async getPricesBySubscription(subscriptionId: string, userId: string): Promise<SubscriptionPriceData> {
    // 1. Найти подписку
    const sub = await this.subsRepo.findOne({ where: { id: subscriptionId, userId } });
    if (!sub) {
      throw new NotFoundException('Подписка не найдена');
    }

    // 2. Определяем формат ключей и строим bid/ask ключи
    let format: 'pipe' | 'concat' = 'concat';
    try {
      const keysResp = await firstValueFrom(
        this.httpService.get<string[]>(`${this.marketDataUrl}/store/keys`),
      );
      format = detectKeyFormat(keysResp.data);
    } catch {
      // используем формат по умолчанию
    }

    const keys = buildStoreKeys(sub.sourceId, sub.pairId, format);
    if (!keys) {
      throw new BadRequestException(
        `Не удалось построить ключи для sourceId="${sub.sourceId}", pairId="${sub.pairId}".`,
      );
    }

    // 3. Запрос к arbiDexMarketData
    const { bidKey, askKey } = keys;
    let botsData: BotsPriceKeysResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.post<BotsPriceKeysResponse>(`${this.marketDataUrl}/store/keys`, {
          keys: [bidKey, askKey],
        }),
      );
      botsData = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе к arbiDexMarketData: ${error.message}`);
      throw new BadRequestException(
        `Не удалось получить данные от сервиса котировок (${this.marketDataUrl}). ` +
        `Убедитесь что arbiDexMarketData запущен.`,
      );
    }

    // 4. Трансформация в формат PriceChartComponent
    const bidPoints: BotsPricePoint[] = botsData[bidKey]?.points ?? [];
    const askPoints: BotsPricePoint[] = botsData[askKey]?.points ?? [];

    // Определяем тип источника: DEX показываем bid/ask, CEX — только mid
    const isDex = sub.sourceId.startsWith('dex');

    // Merge bid и ask по timestamp с помощью Map
    const timeMap = new Map<number, ChartPricePoint>();

    for (const p of bidPoints) {
      timeMap.set(p.t, { time: p.t, bidPrice: p.v, askPrice: 0 });
    }

    for (const p of askPoints) {
      const existing = timeMap.get(p.t);
      if (existing) {
        existing.askPrice = p.v;
      } else {
        timeMap.set(p.t, { time: p.t, bidPrice: 0, askPrice: p.v });
      }
    }

    // Сортировка по времени, заполнение пропусков предыдущим значением
    const sorted = Array.from(timeMap.values()).sort((a, b) => a.time - b.time);

    let lastBid = 0;
    let lastAsk = 0;
    for (const point of sorted) {
      if (point.bidPrice === 0 && lastBid !== 0) point.bidPrice = lastBid;
      if (point.askPrice === 0 && lastAsk !== 0) point.askPrice = lastAsk;
      lastBid = point.bidPrice;
      lastAsk = point.askPrice;
    }

    // 5. Конфиг серий — единый формат bid/ask для всех источников (DEX и CEX)
    const sourceName = SOURCE_META[sub.sourceId]?.displayName ?? sub.sourceId;

    if (isDex) {
      // DEX: две серии — bid и ask
      const series: PriceSeriesConfig[] = [
        { key: 'bidPrice', name: `${sourceName} Bid`, color: '#0ecb81' },
        { key: 'askPrice', name: `${sourceName} Ask`, color: '#f6465d' },
      ];
      return { series, data: sorted };
    } else {
      // CEX: одна серия — mid (среднее bid и ask)
      const midData: ChartPricePoint[] = sorted.map((point) => ({
        time: point.time,
        midPrice:
          point.bidPrice > 0 && point.askPrice > 0
            ? (point.bidPrice + point.askPrice) / 2
            : point.bidPrice || point.askPrice,
      }));

      const series: PriceSeriesConfig[] = [
        { key: 'midPrice', name: `${sourceName} Mid`, color: '#2196f3' },
      ];

      return { series, data: midData };
    }
  }
}

import { Injectable, NotFoundException, BadRequestException, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { buildStoreKeys, detectKeyFormat, SOURCE_META } from './market-data-keys';

/** Точка из PriceStore arbiDexServerBots */
interface BotsPricePoint {
  t: number; // timestamp ms
  v: number; // value
}

/** Ответ от /prices/keys (POST) — каждый ключ содержит объект с полем points */
interface BotsPriceKeyData {
  points: BotsPricePoint[];
  count?: number;
  last?: BotsPricePoint;
}

interface BotsPriceKeysResponse {
  [key: string]: BotsPriceKeyData;
}

/** Конфиг серии для фронтенда */
export interface PriceSeriesConfig {
  key: string;
  name: string;
  color: string;
}

/** Точка данных для фронтенда */
export interface ChartPricePoint {
  time: number;
  [field: string]: number;
}

/** Полный ответ для фронтенда */
export interface SubscriptionPriceData {
  series: PriceSeriesConfig[];
  data: ChartPricePoint[];
}

@Injectable()
export class PricesService {
  private readonly logger = new Logger(PricesService.name);
  private readonly marketDataUrl: string;

  /** TTL кэша — 1 час (в мс) */
  private static readonly CACHE_TTL_MS = 60 * 60 * 1000;

  /** In-memory кэш: subscriptionId → { data, cachedAt } */
  private readonly cache = new Map<string, { data: SubscriptionPriceData; cachedAt: number }>();

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl = this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить ценовые данные по subscriptionId.
   * Маппит sourceId+pairId → ключи PriceStore, запрашивает историю из arbiDexServerBots,
   * трансформирует в формат PriceChartComponent.
   *
   * @param noCache — если true, игнорирует кэш и обновляет его свежими данными
   */
  async getPricesBySubscription(
    subscriptionId: string,
    userId: string,
    noCache = false,
  ): Promise<SubscriptionPriceData> {
    // ── Проверка кэша ──
    if (!noCache) {
      const cached = this.cache.get(subscriptionId);
      if (cached && Date.now() - cached.cachedAt < PricesService.CACHE_TTL_MS) {
        this.logger.debug(`Cache hit для подписки ${subscriptionId} (возраст ${Math.round((Date.now() - cached.cachedAt) / 1000)}с)`);
        return cached.data;
      }
    }
    // 1. Найти подписку
    const sub = await this.subsRepo.findOne({ where: { id: subscriptionId, userId } });
    if (!sub) {
      throw new NotFoundException('Подписка не найдена');
    }

    // 2. Определяем формат ключей и строим bid/ask ключи
    let format: 'pipe' | 'concat' = 'concat';
    try {
      const keysResp = await firstValueFrom(
        this.httpService.get<string[]>(`${this.marketDataUrl}/store/keys`),
      );
      format = detectKeyFormat(keysResp.data);
    } catch {
      // используем формат по умолчанию
    }

    const keys = buildStoreKeys(sub.sourceId, sub.pairId, format);
    if (!keys) {
      throw new BadRequestException(
        `Не удалось построить ключи для sourceId="${sub.sourceId}", pairId="${sub.pairId}".`,
      );
    }

    // 3. Запрос к arbiDexMarketData
    const { bidKey, askKey } = keys;
    let botsData: BotsPriceKeysResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.post<BotsPriceKeysResponse>(`${this.marketDataUrl}/store/keys`, {
          keys: [bidKey, askKey],
        }),
      );
      botsData = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе к arbiDexMarketData: ${error.message}`);
      throw new BadRequestException(
        `Не удалось получить данные от сервиса котировок (${this.marketDataUrl}). ` +
        `Убедитесь что arbiDexMarketData запущен.`,
      );
    }

    // 4. Трансформация в формат PriceChartComponent
    const bidPoints: BotsPricePoint[] = botsData[bidKey]?.points ?? [];
    const askPoints: BotsPricePoint[] = botsData[askKey]?.points ?? [];

    // Определяем тип источника: DEX показываем bid/ask, CEX — только mid
    const isDex = sub.sourceId.startsWith('dex');

    // Merge bid и ask по timestamp с помощью Map
    const timeMap = new Map<number, ChartPricePoint>();

    for (const p of bidPoints) {
      timeMap.set(p.t, { time: p.t, bidPrice: p.v, askPrice: 0 });
    }

    for (const p of askPoints) {
      const existing = timeMap.get(p.t);
      if (existing) {
        existing.askPrice = p.v;
      } else {
        timeMap.set(p.t, { time: p.t, bidPrice: 0, askPrice: p.v });
      }
    }

    // Сортировка по времени, заполнение пропусков предыдущим значением
    const sorted = Array.from(timeMap.values()).sort((a, b) => a.time - b.time);

    let lastBid = 0;
    let lastAsk = 0;
    for (const point of sorted) {
      if (point.bidPrice === 0 && lastBid !== 0) point.bidPrice = lastBid;
      if (point.askPrice === 0 && lastAsk !== 0) point.askPrice = lastAsk;
      lastBid = point.bidPrice;
      lastAsk = point.askPrice;
    }

    // 5. Конфиг серий — единый формат bid/ask для всех источников (DEX и CEX)
    const sourceName = SOURCE_META[sub.sourceId]?.displayName ?? sub.sourceId;

    if (isDex) {
      // DEX: две серии — bid и ask
      const series: PriceSeriesConfig[] = [
        { key: 'bidPrice', name: `${sourceName} Bid`, color: '#0ecb81' },
        { key: 'askPrice', name: `${sourceName} Ask`, color: '#f6465d' },
      ];
      const result: SubscriptionPriceData = { series, data: sorted };
      this.cacheResult(subscriptionId, result);
      return result;
    } else {
      // CEX: одна серия — mid (среднее bid и ask)
      const midData: ChartPricePoint[] = sorted.map((point) => ({
        time: point.time,
        midPrice:
          point.bidPrice > 0 && point.askPrice > 0
            ? (point.bidPrice + point.askPrice) / 2
            : point.bidPrice || point.askPrice,
      }));

      const series: PriceSeriesConfig[] = [
        { key: 'midPrice', name: `${sourceName} Mid`, color: '#2196f3' },
      ];

      const result: SubscriptionPriceData = { series, data: midData };
      this.cacheResult(subscriptionId, result);
      return result;
    }
  }

  /** Сохраняет результат в кэш */
  private cacheResult(subscriptionId: string, data: SubscriptionPriceData): void {
    this.cache.set(subscriptionId, { data, cachedAt: Date.now() });
    this.logger.debug(`Кэш обновлён для подписки ${subscriptionId} (${data.data.length} точек)`);
  }
}

import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  inject,
  OnDestroy,
  OnInit,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Store } from '@ngrx/store';
import { Subscription as RxSubscription, combineLatest } from 'rxjs';
import { take, filter } from 'rxjs/operators';
import { MatButtonModule } from '@angular/material/button';
import { MatButtonToggleModule } from '@angular/material/button-toggle';
import { MatIconModule } from '@angular/material/icon';
import { MatChipsModule } from '@angular/material/chips';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatTooltipModule } from '@angular/material/tooltip';
import { MatSnackBar, MatSnackBarModule } from '@angular/material/snack-bar';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';
import {
  PriceChartComponent,
  PriceSeriesConfig,
  PricePoint,
  HorizontalLine,
  TradeMarker,
} from '../../shared/ui/price-chart/price-chart.component';
import { PageContainerComponent } from '../../shared/ui/page-container/page-container.component';
import { PageHeaderComponent } from '../../shared/ui/page-header/page-header.component';
import { ContentCardComponent } from '../../shared/ui/content-card/content-card.component';
import { LoadingStateComponent } from '../../shared/ui/loading-state/loading-state.component';
import { StatCardComponent } from '../../shared/ui/stat-card/stat-card.component';
import { PlaybackPlayerComponent } from '../../shared/ui/playback-player/playback-player.component';
import { ArbiConfigsFacade } from '../../features/arbi-configs/facades/arbi-configs.facade';
import { CatalogFacade } from '../../features/catalog/facades/catalog.facade';
import { DemoAccountFacade } from '../../features/demo-account/facades/demo-account.facade';
import {
  LiveChartSocketService,
  MultiLiveChartMessage,
} from '../../features/live-chart/services/live-chart-socket.service';
import { MultiPlaybackService, MultiPlaybackTick } from '../../features/arbi-configs/services/multi-playback.service';
import { AutoTradeEngine } from '../../features/arbi-configs/engine/auto-trade.engine';
import { selectAccessToken } from '../../features/auth/store/auth.selectors';
import {
  buildMultiChart,
  extractFieldKey,
  ChartSubscriptionInfo,
  MultiChartResult,
} from '../../shared/utils/multi-chart-builder';
import {
  ArbiConfig,
  Source,
  TradingPair,
  SwapDirection,
  DemoTrade,
  PlaybackState,
  PlaybackSpeed,
} from '../../shared/models';

const MAX_CHART_POINTS = 2000;

type PageMode = 'historical' | 'live' | 'playback';

@Component({
  selector: 'app-arbi-config-detail-page',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    FormsModule,
    RouterModule,
    MatButtonModule,
    MatButtonToggleModule,
    MatIconModule,
    MatChipsModule,
    MatFormFieldModule,
    MatInputModule,
    MatTooltipModule,
    MatSnackBarModule,
    MatSlideToggleModule,
    PriceChartComponent,
    PageContainerComponent,
    PageHeaderComponent,
    ContentCardComponent,
    LoadingStateComponent,
    StatCardComponent,
    PlaybackPlayerComponent,
  ],
  template: `
    <app-page-container>
      <app-page-header
        [title]="config?.name ?? 'Config'"
        subtitle="Arbitrage config detail — chart, trading & auto-trade">
        <div slot="actions" class="header-actions">
          <mat-button-toggle-group
            [value]="mode"
            (change)="onModeChange($event.value)"
            appearance="standard"
            class="mode-toggle">
            <mat-button-toggle value="historical">
              <mat-icon>history</mat-icon> Historical
            </mat-button-toggle>
            <mat-button-toggle value="playback">
              <mat-icon>play_circle</mat-icon> Playback
            </mat-button-toggle>
            <mat-button-toggle value="live">
              <mat-icon>wifi</mat-icon> Live
            </mat-button-toggle>
          </mat-button-toggle-group>

          <button mat-stroked-button [routerLink]="['/arbi-configs', configId, 'edit']">
            <mat-icon>edit</mat-icon> Edit
          </button>
          <button mat-stroked-button color="warn" (click)="onDelete()">
            <mat-icon>delete</mat-icon> Delete
          </button>
          <button mat-stroked-button routerLink="/arbi-configs">
            <mat-icon>arrow_back</mat-icon> Back
          </button>
        </div>
      </app-page-header>

      <!-- Config info cards -->
      <div class="info-row" *ngIf="config">
        <app-stat-card label="Trading" [value]="tradingLabel" icon="swap_horiz" color="purple" />
        <app-stat-card label="Profit Asset" [value]="config.profitAsset" icon="attach_money" color="green" />
        <app-stat-card label="Slippage" [value]="(config.slippage * 100 | number:'1.1-2') + '%'" icon="trending_flat" color="orange" />
        <app-stat-card label="Balance" [value]="(config.initialBalance | number:'1.0-2') ?? '0'" icon="account_balance" color="blue" />
      </div>

      <!-- Reference sources chips -->
      <app-content-card *ngIf="config" title="Reference Sources" [compact]="true">
        <div class="ref-chips">
          <span class="chip" *ngFor="let label of referenceLabels">{{ label }}</span>
        </div>
      </app-content-card>

      <!-- ── PLAYBACK MODE: Player Controls ── -->
      <ng-container *ngIf="mode === 'playback'">
        <app-content-card title="Playback Controls" [compact]="true">
          <div *ngIf="playbackState.loading" class="playback-loading">
            <mat-icon>hourglass_top</mat-icon> Loading historical data…
          </div>
          <div *ngIf="playbackState.error" class="error-msg">
            <mat-icon>error_outline</mat-icon>
            <span>{{ playbackState.error }}</span>
          </div>
          <app-playback-player
            *ngIf="!playbackState.loading && !playbackState.error && playbackState.totalPoints > 0"
            [state]="playbackState"
            (play)="onPlaybackPlay()"
            (pause)="onPlaybackPause()"
            (stop)="onPlaybackStop()"
            (speedChange)="onPlaybackSpeedChange($event)"
            (seek)="onPlaybackSeek($event)" />
        </app-content-card>
      </ng-container>

      <!-- Chart -->
      <app-loading-state *ngIf="loading" label="Loading price data…" />

      <div *ngIf="error" class="error-msg">
        <mat-icon>error_outline</mat-icon>
        <span>{{ error }}</span>
      </div>

      <app-content-card *ngIf="!loading && !error && series.length > 0" title="Price Chart">
        <ng-container slot="header-actions">
          <div class="live-badge" *ngIf="mode === 'live'">
            <span class="dot"></span> LIVE
          </div>
          <div class="live-badge live-badge--playback" *ngIf="mode === 'playback' && playbackState.isPlaying">
            <span class="dot"></span> PLAYBACK {{ playbackState.speed }}×
          </div>
          <button mat-icon-button
                  (click)="chartVisible = !chartVisible"
                  [matTooltip]="chartVisible ? 'Hide chart' : 'Show chart'">
            <mat-icon>{{ chartVisible ? 'expand_less' : 'expand_more' }}</mat-icon>
          </button>
        </ng-container>
        <app-price-chart
          *ngIf="chartVisible"
          [series]="series"
          [data]="chartData"
          [horizontalLines]="hLines"
          [tradeMarkers]="tradeMarkersList"
          [streaming]="false" />
      </app-content-card>

      <!-- ── TRADING SECTION (only in playback / live) ── -->
      <ng-container *ngIf="config && (mode === 'playback' || mode === 'live')">

        <!-- Balance cards -->
        <div class="info-row" style="margin-top: 16px;">
          <app-stat-card label="USDC Balance"
            [value]="(usdcBalance | number:'1.2-2') ?? '0.00'"
            icon="attach_money" color="green" />
          <app-stat-card label="WETH Balance"
            [value]="(wethBalance | number:'1.4-8') ?? '0.00000000'"
            icon="currency_exchange" color="purple" />
          <app-stat-card label="Portfolio (USDC)"
            [value]="(portfolioValue | number:'1.2-2') ?? '0.00'"
            icon="account_balance"
            [color]="pnl >= 0 ? 'green' : 'orange'" />
          <app-stat-card label="P&L"
            [value]="pnlDisplay"
            icon="trending_up"
            [color]="pnl >= 0 ? 'green' : 'orange'" />
        </div>

        <!-- Quote info -->
        <app-content-card *ngIf="tradingMid > 0" title="Trading Source Quote" [compact]="true">
          <div class="quote-info-row">
            <div class="quote-item quote-item--bid">
              <span class="quote-item__label">Bid</span>
              <span class="quote-item__value">{{ tradingBid | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item quote-item--ask">
              <span class="quote-item__label">Ask</span>
              <span class="quote-item__value">{{ tradingAsk | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item">
              <span class="quote-item__label">Mid</span>
              <span class="quote-item__value">{{ tradingMid | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item">
              <span class="quote-item__label">Avg Ref Mid</span>
              <span class="quote-item__value">{{ avgRefMid | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item" *ngIf="engine?.hasPosition">
              <span class="quote-item__label">Peak</span>
              <span class="quote-item__value">{{ engine!.peakSellPrice | number:'1.2-4' }}</span>
            </div>
          </div>
        </app-content-card>

        <!-- Auto-trade toggle + Manual swap -->
        <app-content-card title="Trading" [elevated]="true">
          <div class="trading-header">
            <mat-slide-toggle [(ngModel)]="autoTradeEnabled" class="auto-toggle">
              Auto-Trade
            </mat-slide-toggle>
            <span class="auto-status" *ngIf="autoTradeEnabled && engine">
              {{ engine.hasPosition ? ' In Position' : '⏳ Waiting for signal' }}
            </span>
            <span class="auto-reason" *ngIf="lastAutoTradeReason">{{ lastAutoTradeReason }}</span>
          </div>

          <!-- Manual swap form -->
          <div class="swap-form" *ngIf="!autoTradeEnabled">
            <div class="swap-row">
              <mat-form-field appearance="outline" class="swap-field">
                <mat-label>{{ direction === 'USDC_TO_WETH' ? 'Spend USDC' : 'Spend WETH' }}</mat-label>
                <input matInput type="number" [(ngModel)]="amountIn" (ngModelChange)="recalcEstimate()"
                       min="0" [step]="direction === 'USDC_TO_WETH' ? 10 : 0.001" />
                <span matTextSuffix class="token-suffix">{{ direction === 'USDC_TO_WETH' ? 'USDC' : 'WETH' }}</span>
              </mat-form-field>

              <button mat-icon-button class="flip-btn" (click)="flipDirection()" matTooltip="Flip direction">
                <mat-icon>swap_vert</mat-icon>
              </button>

              <div class="estimate-box">
                <span class="estimate-label">You receive ≈</span>
                <span class="estimate-value">
                  {{ estimatedOut | number:(direction === 'USDC_TO_WETH' ? '1.4-8' : '1.2-4') }}
                  {{ direction === 'USDC_TO_WETH' ? 'WETH' : 'USDC' }}
                </span>
              </div>
            </div>

            <div class="action-row">
              <button mat-stroked-button (click)="setMax()">MAX</button>
              <button mat-flat-button color="primary" class="swap-btn"
                      [disabled]="!canSwap"
                      (click)="doSwap()">
                <mat-icon>swap_horiz</mat-icon>
                {{ direction === 'USDC_TO_WETH' ? 'Buy WETH' : 'Sell WETH' }}
              </button>
            </div>
          </div>
        </app-content-card>

        <!-- Trade History -->
        <app-content-card [title]="'Trade History (' + trades.length + ')'" *ngIf="trades.length > 0">
          <button slot="header-actions" mat-icon-button
                  (click)="showTradeHistory = !showTradeHistory"
                  [matTooltip]="showTradeHistory ? 'Hide table' : 'Show table'">
            <mat-icon>{{ showTradeHistory ? 'expand_less' : 'expand_more' }}</mat-icon>
          </button>
          <div class="trade-table-wrap" *ngIf="showTradeHistory">
            <table class="trade-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Step</th>
                  <th>Direction</th>
                  <th>Spent</th>
                  <th>Received</th>
                  <th>Price</th>
                  <th>Time</th>
                </tr>
              </thead>
              <tbody>
                <tr *ngFor="let t of trades">
                  <td>{{ t.id }}</td>
                  <td>{{ t.step != null ? t.step : '—' }}</td>
                  <td>
                    <span [class]="t.direction === 'USDC_TO_WETH' ? 'dir-buy' : 'dir-sell'">
                      {{ t.direction === 'USDC_TO_WETH' ? 'BUY' : 'SELL' }}
                    </span>
                  </td>
                  <td>{{ t.amountIn | number:(t.tokenIn === 'USDC' ? '1.2-2' : '1.4-8') }} {{ t.tokenIn }}</td>
                  <td>{{ t.amountOut | number:(t.tokenOut === 'USDC' ? '1.2-2' : '1.4-8') }} {{ t.tokenOut }}</td>
                  <td>{{ t.price | number:'1.2-4' }}</td>
                  <td>{{ (t.playbackTime ?? t.timestamp) | date:'HH:mm:ss' }}</td>
                </tr>
              </tbody>
            </table>
          </div>
        </app-content-card>

      </ng-container>
    </app-page-container>
  `,
  styles: [`
    @use 'styles/tokens' as t;

    .header-actions {
      display: flex;
      align-items: center;
      gap: 8px;
      flex-wrap: wrap;
    }

    .mode-toggle { margin-right: 8px; }

    .info-row {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
      gap: t.$spacing-sm;
      margin-bottom: t.$spacing-md;
    }

    .ref-chips { display: flex; flex-wrap: wrap; gap: 6px; }

    .chip {
      font-size: 12px;
      padding: 4px 12px;
      border-radius: 16px;
      background: var(--color-background);
      color: var(--color-text-secondary);
      border: 1px solid var(--color-border);
    }

    .error-msg {
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 16px;
      color: var(--color-danger, #ef4444);
      justify-content: center;
    }

    .playback-loading {
      display: flex;
      align-items: center;
      gap: 8px;
      color: var(--color-text-muted);
      padding: 8px 0;
    }


    .live-badge, .live-badge--playback {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 4px 10px;
      background: rgba(14, 203, 129, 0.15);
      border: 1px solid #0ecb81;
      border-radius: 4px;
      color: #0ecb81;
      font-size: 12px;
      font-weight: 600;
      letter-spacing: 1px;
      .dot {
        width: 8px; height: 8px; border-radius: 50%;
        background: currentColor;
        animation: pulse 1.5s ease-in-out infinite;
      }
    }
    .live-badge--playback {
      background: rgba(33, 150, 243, 0.15);
      border-color: #2196f3;
      color: #2196f3;
    }

    @keyframes pulse {
      0%, 100% { opacity: 1; }
      50%       { opacity: 0.2; }
    }

    app-content-card { display: block; margin-bottom: t.$spacing-md; }

    /* ── Quote info ── */
    .quote-info-row {
      display: flex;
      gap: t.$spacing-lg;
      flex-wrap: wrap;
      align-items: flex-end;
    }
    .quote-item {
      display: flex; flex-direction: column; gap: 2px;
      &__label {
        font-size: t.$font-size-xs;
        color: var(--color-text-muted);
        text-transform: uppercase;
        letter-spacing: 0.5px;
      }
      &__value {
        font-size: t.$font-size-lg;
        font-weight: t.$font-weight-bold;
        color: var(--color-text-primary);
      }
      &--bid .quote-item__value { color: #0ecb81; }
      &--ask .quote-item__value { color: #f6465d; }
    }

    /* ── Trading section ── */
    .trading-header {
      display: flex;
      align-items: center;
      gap: t.$spacing-md;
      margin-bottom: t.$spacing-md;
      flex-wrap: wrap;
    }
    .auto-toggle { font-weight: 600; }
    .auto-status {
      font-size: t.$font-size-sm;
      color: var(--color-text-secondary);
    }
    .auto-reason {
      font-size: t.$font-size-xs;
      color: var(--color-text-muted);
      font-style: italic;
    }

    .swap-form {
      display: flex;
      flex-direction: column;
      gap: t.$spacing-md;
    }
    .swap-row {
      display: flex;
      align-items: center;
      gap: t.$spacing-md;
      flex-wrap: wrap;
    }
    .swap-field { flex: 1; min-width: 200px; }
    .flip-btn {
      color: var(--color-text-secondary);
      transition: transform 0.3s ease;
      &:hover { transform: rotate(180deg); color: var(--color-text-primary); }
    }
    .estimate-box {
      flex: 1; min-width: 180px;
      display: flex; flex-direction: column;
      padding: t.$spacing-md;
      background: var(--color-background);
      border: 1px solid var(--color-border);
      border-radius: t.$radius-sm;
    }
    .estimate-label {
      font-size: t.$font-size-xs;
      color: var(--color-text-muted);
      margin-bottom: 4px;
    }
    .estimate-value {
      font-size: t.$font-size-lg;
      font-weight: t.$font-weight-bold;
      color: var(--color-text-primary);
    }
    .token-suffix {
      font-weight: t.$font-weight-semibold;
      color: var(--color-text-muted);
    }
    .action-row { display: flex; align-items: center; gap: t.$spacing-md; }
    .swap-btn {
      flex: 1; height: 48px;
      font-size: t.$font-size-base;
      font-weight: t.$font-weight-semibold;
    }

    /* Trade table */
    .trade-table-wrap { overflow-x: auto; }
    .trade-table {
      width: 100%; border-collapse: collapse; font-size: t.$font-size-sm;
      th, td {
        padding: 8px 12px; text-align: left;
        border-bottom: 1px solid var(--color-border);
        white-space: nowrap;
      }
      th {
        color: var(--color-text-muted);
        font-weight: t.$font-weight-semibold;
        font-size: t.$font-size-xs;
        text-transform: uppercase;
        letter-spacing: 0.5px;
      }
      td { color: var(--color-text-primary); }
    }
    .dir-buy { color: #0ecb81; font-weight: 600; }
    .dir-sell { color: #f6465d; font-weight: 600; }
  `],
})
export class ArbiConfigDetailPageComponent implements OnInit, OnDestroy {
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);
  private readonly store = inject(Store);
  private readonly configsFacade = inject(ArbiConfigsFacade);
  private readonly catalogFacade = inject(CatalogFacade);
  private readonly demoFacade = inject(DemoAccountFacade);
  private readonly liveChartSocket = inject(LiveChartSocketService);
  private readonly multiPlayback = inject(MultiPlaybackService);
  private readonly snackBar = inject(MatSnackBar);
  private readonly cdr = inject(ChangeDetectorRef);

  configId = '';
  config: ArbiConfig | null = null;
  mode: PageMode = 'historical';

  tradingLabel = '';
  referenceLabels: string[] = [];

  // Chart
  series: PriceSeriesConfig[] = [];
  chartData: PricePoint[] = [];
  hLines: HorizontalLine[] = [];
  loading = true;
  error = '';
  chartVisible = true;

  // Playback
  playbackState: PlaybackState = {
    isPlaying: false, speed: 1, currentTime: 0, startTime: 0, endTime: 0,
    progress: 0, totalPoints: 0, currentIndex: 0, loading: false, error: '',
  };
  private allPlaybackPoints: PricePoint[] = [];

  // Trading prices
  tradingBid = 0;
  tradingAsk = 0;
  tradingMid = 0;
  avgRefMid = 0;

  // Demo account
  usdcBalance = 100;
  wethBalance = 0;
  initialUsdc = 100;
  portfolioValue = 100;
  pnl = 0;
  pnlDisplay = '+0.00 USDC';

  // Swap form
  direction: SwapDirection = 'USDC_TO_WETH';
  amountIn = 100;
  estimatedOut = 0;
  trades: DemoTrade[] = [];
  tradeMarkersList: TradeMarker[] = [];
  showTradeHistory = false;

  // Auto-trade
  autoTradeEnabled = false;
  engine: AutoTradeEngine | null = null;
  lastAutoTradeReason = '';

  // Актуальный step/time из последнего тика (не из state, т.к. state обновляется после батча)
  private lastTickIndex = 0;
  private lastTickTime = 0;

  private keyPrefixMap = new Map<string, string>();
  private allSubscriptionIds: string[] = [];
  private tradingSubId = '';
  private referenceSubIds: string[] = [];
  private liveValues = new Map<string, { bid: number; ask: number; mid: number }>();
  private chartSubs: ChartSubscriptionInfo[] = [];
  private rxSubs: RxSubscription[] = [];

  get canSwap(): boolean {
    if (this.amountIn <= 0 || this.tradingMid <= 0) return false;
    if (this.direction === 'USDC_TO_WETH') return this.amountIn <= this.usdcBalance;
    return this.amountIn <= this.wethBalance;
  }

  ngOnInit(): void {
    this.configId = this.route.snapshot.paramMap.get('id') ?? '';
    this.catalogFacade.loadAll();
    this.configsFacade.loadOne(this.configId);
    this.configsFacade.loadPrices(this.configId);

    // Wait for config + catalog to resolve labels
    const configSub = combineLatest([
      this.configsFacade.selectById(this.configId),
      this.catalogFacade.sources$,
      this.catalogFacade.pairs$,
    ]).pipe(
      filter(([c, sources]) => !!c && sources.length > 0),
    ).subscribe(([config, sources, pairs]) => {
      if (!config) return;
      this.config = config;

      const sourceMap = new Map(sources.map((s: Source) => [s.id, s]));
      const pairMap = new Map(pairs.map((p: TradingPair) => [p.id, p]));

      this.tradingLabel = this.makeLabel(config.tradingSourceId, config.tradingPairId, sourceMap, pairMap);
      this.referenceLabels = config.sources.map((s) =>
        this.makeLabel(s.sourceId, s.pairId, sourceMap, pairMap),
      );

      this.tradingSubId = config.tradingSubscriptionId;
      this.referenceSubIds = config.sources.map((s) => s.subscriptionId);

      // Init demo balance from config
      this.demoFacade.setInitialBalance(config.initialBalance);
      this.amountIn = config.initialBalance;

      // Init auto-trade engine
      this.engine = new AutoTradeEngine(config);

      this.cdr.markForCheck();
    });
    this.rxSubs.push(configSub);

    // Wait for prices (historical mode chart data)
    const pricesSub = combineLatest([
      this.configsFacade.currentPrices$,
      this.configsFacade.selectById(this.configId),
      this.catalogFacade.sources$,
      this.catalogFacade.pairs$,
    ]).pipe(
      filter(([prices, config, sources]) => !!prices && !!config && sources.length > 0),
      take(1),
    ).subscribe(([pricesResp, config, sources, pairs]) => {
      if (!pricesResp || !config) return;

      const sourceMap = new Map(sources.map((s: Source) => [s.id, s]));
      const pairMap = new Map(pairs.map((p: TradingPair) => [p.id, p]));

      this.chartSubs = [];
      this.chartSubs.push({
        id: config.tradingSubscriptionId,
        label: this.makeLabel(config.tradingSourceId, config.tradingPairId, sourceMap, pairMap),
        role: 'trading',
      });
      config.sources.forEach((s) => {
        this.chartSubs.push({
          id: s.subscriptionId,
          label: this.makeLabel(s.sourceId, s.pairId, sourceMap, pairMap),
          role: 'reference',
        });
      });

      const result: MultiChartResult = buildMultiChart(this.chartSubs, pricesResp.prices);
      this.series = result.series;
      this.chartData = result.data;
      this.keyPrefixMap = result.keyPrefixMap;
      this.allSubscriptionIds = this.chartSubs.map((s) => s.id);
      this.loading = false;
      this.cdr.markForCheck();
    });
    this.rxSubs.push(pricesSub);

    // Handle price loading error
    const errSub = this.configsFacade.error$.pipe(
      filter((e) => !!e),
      take(1),
    ).subscribe((err) => {
      this.error = err ?? 'Failed to load data';
      this.loading = false;
      this.cdr.markForCheck();
    });
    this.rxSubs.push(errSub);

    // Subscribe to demo account state
    const demoSub = combineLatest([
      this.demoFacade.usdcBalance$,
      this.demoFacade.wethBalance$,
      this.demoFacade.initialUsdc$,
      this.demoFacade.tradeHistory$,
    ]).subscribe(([usdc, weth, initial, history]) => {
      this.usdcBalance = usdc;
      this.wethBalance = weth;
      this.initialUsdc = initial;
      this.trades = history;
      this.updateTradeMarkers();
      this.updatePortfolio();
      this.recalcEstimate();
      this.cdr.markForCheck();
    });
    this.rxSubs.push(demoSub);

    // Subscribe to playback state
    const pbStateSub = this.multiPlayback.state$.subscribe((s) => {
      this.playbackState = s;
      this.cdr.markForCheck();
    });
    this.rxSubs.push(pbStateSub);
  }

  ngOnDestroy(): void {
    this.rxSubs.forEach((s) => s.unsubscribe());
    this.liveChartSocket.disconnectAll();
    this.multiPlayback.stop();
  }

  /* ── Mode switching ── */

  onModeChange(newMode: string): void {
    const m = newMode as PageMode;
    if (m === this.mode) return;

    if (this.mode === 'live') this.liveChartSocket.disconnectAll();
    if (this.mode === 'playback') this.multiPlayback.stop();

    this.mode = m;

    if (m === 'live') {
      this.connectSockets();
    } else if (m === 'playback') {
      this.startPlaybackMode();
    }
    this.cdr.markForCheck();
  }

  onDelete(): void {
    if (confirm('Are you sure you want to delete this config?')) {
      this.configsFacade.delete(this.configId);
    }
  }

  /* ── Playback controls ── */

  onPlaybackPlay(): void { this.multiPlayback.play(); }
  onPlaybackPause(): void { this.multiPlayback.pause(); }

  onPlaybackStop(): void {
    this.multiPlayback.stop();
    this.resetTradeState();
    this.startPlaybackMode();
  }

  onPlaybackSpeedChange(speed: PlaybackSpeed): void {
    this.multiPlayback.setSpeed(speed);
  }

  onPlaybackSeek(progress: number): void {
    this.multiPlayback.seekTo(progress);
    if (this.allPlaybackPoints.length > 0) {
      const idx = Math.min(
        Math.floor(progress * this.allPlaybackPoints.length),
        this.allPlaybackPoints.length - 1,
      );
      this.chartData = this.allPlaybackPoints.slice(0, idx + 1);
      this.cdr.markForCheck();
    }
  }

  /* ── Manual swap ── */

  flipDirection(): void {
    if (this.direction === 'USDC_TO_WETH') {
      this.direction = 'WETH_TO_USDC';
      this.amountIn = this.wethBalance;
    } else {
      this.direction = 'USDC_TO_WETH';
      this.amountIn = this.usdcBalance;
    }
    this.recalcEstimate();
  }

  setMax(): void {
    this.amountIn = this.direction === 'USDC_TO_WETH' ? this.usdcBalance : this.wethBalance;
    this.recalcEstimate();
  }

  recalcEstimate(): void {
    if (this.tradingMid <= 0 || this.amountIn <= 0) {
      this.estimatedOut = 0;
      return;
    }
    const slip = this.config?.slippage ?? 0.01;
    if (this.direction === 'USDC_TO_WETH') {
      const price = this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid;
      this.estimatedOut = this.amountIn / (price * (1 + slip));
    } else {
      const price = this.tradingBid > 0 ? this.tradingBid : this.tradingMid;
      this.estimatedOut = this.amountIn * (price * (1 - slip));
    }
  }

  doSwap(): void {
    if (!this.canSwap) return;
    const slip = this.config?.slippage ?? 0.01;
    const { step, playbackTime } = this.currentPlaybackInfo();
    // Покупка по ask, продажа по bid (как на реальном рынке)
    const execPrice = this.direction === 'USDC_TO_WETH'
      ? (this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid)
      : (this.tradingBid > 0 ? this.tradingBid : this.tradingMid);
    this.demoFacade.swap(this.direction, this.amountIn, slip, execPrice, step, playbackTime);
    this.snackBar.open(
      `Swap: ${this.amountIn.toFixed(2)} ${this.direction === 'USDC_TO_WETH' ? 'USDC → WETH' : 'WETH → USDC'}`,
      'OK', { duration: 3000 },
    );

    if (this.engine) {
      if (this.direction === 'USDC_TO_WETH') {
        this.engine.onBuy(this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid);
      } else {
        this.engine.onSell();
      }
    }
    this.updateHorizontalLines();
  }

  /* ── Playback Mode ── */

  private startPlaybackMode(): void {
    if (this.chartSubs.length === 0) return;

    // Используем данные из store — те же, что и для historical режима
    const sub = this.configsFacade.currentPrices$.pipe(
      filter((prices) => !!prices),
      take(1),
    ).subscribe((pricesResp) => {
      if (!pricesResp) return;

      const result = this.multiPlayback.loadFromData(this.chartSubs, pricesResp.prices);
      if (!result || result.data.length === 0) return;

      this.series = result.series;
      this.allPlaybackPoints = [...result.data];
      this.keyPrefixMap = result.keyPrefixMap;
      this.chartData = [];
      this.cdr.markForCheck();

      const tickSub = this.multiPlayback.tick$.subscribe((tick) => {
        this.onPlaybackTick(tick);
      });
      this.rxSubs.push(tickSub);
    });
    this.rxSubs.push(sub);
  }

  private onPlaybackTick(tick: MultiPlaybackTick): void {
    // Сохраняем актуальный step/time из тика (state обновляется после батча, а тик — для каждой точки)
    this.lastTickIndex = tick.index;
    this.lastTickTime = tick.time;

    // Only update chart data if chart is visible (major performance gain)
    if (this.chartVisible) {
      const targetLen = tick.index + 1;
      if (targetLen <= this.allPlaybackPoints.length && this.chartData.length < targetLen) {
        this.chartData = this.allPlaybackPoints.slice(0, targetLen);
      }
    }

    this.extractPricesFromTick(tick);
    this.runAutoTrade();
    this.updatePortfolio();
    this.updateHorizontalLines();
    this.cdr.markForCheck();
  }

  /* ── WebSocket (Live Mode) ── */

  private connectSockets(): void {
    if (this.allSubscriptionIds.length === 0) return;

    this.store
      .select(selectAccessToken)
      .pipe(take(1))
      .subscribe((token) => {
        if (!token) return;

        this.liveChartSocket.disconnectAll();
        const wsSub = this.liveChartSocket
          .connectMultiple(token, this.allSubscriptionIds)
          .subscribe({
            next: (msg) => this.onLivePriceUpdate(msg),
            error: (err) => console.error('ArbiConfig LiveChart WS error:', err),
          });
        this.rxSubs.push(wsSub);
      });
  }

  private onLivePriceUpdate(msg: MultiLiveChartMessage): void {
    const prefix = this.keyPrefixMap.get(msg.subscriptionId);
    if (!prefix) return;

    const fieldKey = extractFieldKey(msg.key);

    // Only update chart data if chart is visible
    if (this.chartVisible) {
      const newFieldKey = `${prefix}_${fieldKey}`;
      const last = this.chartData[this.chartData.length - 1];
      const newPoint: PricePoint = {
        ...(last ?? {}),
        time: msg.point.t,
        [newFieldKey]: msg.point.v,
      };
      let updated = [...this.chartData, newPoint];
      if (updated.length > MAX_CHART_POINTS) {
        updated = updated.slice(updated.length - MAX_CHART_POINTS);
      }
      this.chartData = updated;
    }

    // Update live values (always, for trading logic)
    const existing = this.liveValues.get(msg.subscriptionId) ?? { bid: 0, ask: 0, mid: 0 };
    const keyLower = fieldKey.toLowerCase();
    if (keyLower.includes('bid')) existing.bid = msg.point.v;
    else if (keyLower.includes('ask')) existing.ask = msg.point.v;
    else if (keyLower.includes('mid')) existing.mid = msg.point.v;
    if (existing.bid > 0 && existing.ask > 0 && existing.mid === 0) {
      existing.mid = (existing.bid + existing.ask) / 2;
    }
    this.liveValues.set(msg.subscriptionId, existing);

    this.derivePricesFromLive();
    this.runAutoTrade();
    this.updatePortfolio();
    this.updateHorizontalLines();
    this.cdr.markForCheck();
  }

  /* ── Price extraction ── */

  private extractPricesFromTick(tick: MultiPlaybackTick): void {
    const trading = tick.values.get(this.tradingSubId);
    if (trading) {
      this.tradingBid = trading.bid;
      this.tradingAsk = trading.ask;
      this.tradingMid = trading.mid;
    }

    let refSum = 0;
    let refCount = 0;
    for (const refId of this.referenceSubIds) {
      const ref = tick.values.get(refId);
      if (ref && ref.mid > 0) {
        refSum += ref.mid;
        refCount++;
      }
    }
    this.avgRefMid = refCount > 0 ? refSum / refCount : 0;
  }

  private derivePricesFromLive(): void {
    const trading = this.liveValues.get(this.tradingSubId);
    if (trading) {
      if (trading.bid > 0) this.tradingBid = trading.bid;
      if (trading.ask > 0) this.tradingAsk = trading.ask;
      if (trading.bid > 0 && trading.ask > 0) {
        this.tradingMid = (trading.bid + trading.ask) / 2;
      } else if (trading.mid > 0) {
        this.tradingMid = trading.mid;
      }
    }

    let refSum = 0;
    let refCount = 0;
    for (const refId of this.referenceSubIds) {
      const ref = this.liveValues.get(refId);
      if (ref) {
        const mid = ref.mid > 0 ? ref.mid : (ref.bid > 0 && ref.ask > 0 ? (ref.bid + ref.ask) / 2 : 0);
        if (mid > 0) { refSum += mid; refCount++; }
      }
    }
    this.avgRefMid = refCount > 0 ? refSum / refCount : 0;
  }

  /* ── Auto-Trade Engine ── */

  private runAutoTrade(): void {
    if (!this.autoTradeEnabled || !this.engine || !this.config) return;
    if (this.tradingBid <= 0 || this.tradingAsk <= 0 || this.avgRefMid <= 0) return;

    const result = this.engine.tick(this.tradingBid, this.tradingAsk, this.avgRefMid);

    if (result.action === 'buy') {
      const tradeAmountPct = this.config.tradeAmountPct ?? 100;
      const amount = this.usdcBalance * (tradeAmountPct / 100);
      if (amount > 0) {
        const { step, playbackTime } = this.currentPlaybackInfo();
        // Покупка по ask (как на реальном рынке)
        const buyPrice = this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid;
        this.demoFacade.swap('USDC_TO_WETH', amount, this.config.slippage, buyPrice, step, playbackTime);
        this.engine.onBuy(this.tradingAsk);
        this.lastAutoTradeReason = result.reason ?? 'Auto-buy';
        this.snackBar.open(` Auto-BUY: ${amount.toFixed(2)} USDC`, 'OK', { duration: 3000 });
      }
    } else if (result.action === 'sell') {
      if (this.wethBalance > 0) {
        const { step, playbackTime } = this.currentPlaybackInfo();
        // Продажа по bid (как на реальном рынке)
        const sellPrice = this.tradingBid > 0 ? this.tradingBid : this.tradingMid;
        this.demoFacade.swap('WETH_TO_USDC', this.wethBalance, this.config.slippage, sellPrice, step, playbackTime);
        this.engine.onSell();
        this.lastAutoTradeReason = result.reason ?? 'Auto-sell';
        this.snackBar.open(` Auto-SELL: ${this.wethBalance.toFixed(8)} WETH`, 'OK', { duration: 3000 });
      }
    }
  }

  /* ── Horizontal Lines ── */

  private updateHorizontalLines(): void {
    const lines: HorizontalLine[] = [];

    if (this.engine && this.engine.hasPosition) {
      if (this.engine.buyPrice > 0) {
        lines.push({ value: this.engine.buyPrice, color: '#0ecb81', label: 'Buy Price' });
      }
      if (this.engine.trailingSellLevel > 0) {
        lines.push({ value: this.engine.trailingSellLevel, color: '#2196f3', label: 'Trailing TP' });
      }
      const slLevel = this.engine.stopLossLevel;
      if (slLevel > 0) {
        lines.push({ value: slLevel, color: '#f6465d', label: 'Stop Loss' });
      }
      if (this.engine.peakSellPrice > 0) {
        lines.push({ value: this.engine.peakSellPrice, color: '#ff9800', label: 'Peak', dash: true });
      }
    } else if (this.engine && !this.engine.hasPosition && this.avgRefMid > 0) {
      const autoBuyLevel = this.engine.getAutoBuyLevel(this.avgRefMid);
      if (autoBuyLevel > 0) {
        lines.push({ value: autoBuyLevel, color: '#ffeb3b', label: 'Auto-Buy Level' });
      }
    }

    this.hLines = lines;
  }

  /* ── Helpers ── */

  /** Возвращает текущий номер шага и время playback (если в playback-режиме) */
  private currentPlaybackInfo(): { step?: number; playbackTime?: number } {
    if (this.mode === 'playback') {
      return { step: this.lastTickIndex, playbackTime: this.lastTickTime };
    }
    return {};
  }

  private updateTradeMarkers(): void {
    this.tradeMarkersList = this.trades.map((t) => ({
      time: t.playbackTime ?? t.timestamp,
      price: t.price,
      direction: t.direction === 'USDC_TO_WETH' ? 'buy' as const : 'sell' as const,
      label: t.direction === 'USDC_TO_WETH' ? 'BUY' : 'SELL',
    }));
  }

  private updatePortfolio(): void {
    if (this.tradingMid > 0) {
      this.portfolioValue = this.usdcBalance + this.wethBalance * this.tradingMid;
    } else {
      this.portfolioValue = this.usdcBalance;
    }
    this.pnl = this.portfolioValue - this.initialUsdc;
    const sign = this.pnl >= 0 ? '+' : '';
    this.pnlDisplay = `${sign}${this.pnl.toFixed(2)} USDC`;
  }

  private resetTradeState(): void {
    this.demoFacade.setInitialBalance(this.config?.initialBalance ?? 100);
    this.engine?.reset();
    this.lastAutoTradeReason = '';
    this.tradingBid = 0;
    this.tradingAsk = 0;
    this.tradingMid = 0;
    this.avgRefMid = 0;
    this.hLines = [];
    this.direction = 'USDC_TO_WETH';
  }

  private makeLabel(
    sourceId?: string,
    pairId?: string,
    sourceMap?: Map<string, Source>,
    pairMap?: Map<string, TradingPair>,
  ): string {
    if (!sourceId || !pairId) return 'Unknown';
    const src = sourceMap?.get(sourceId)?.displayName ?? sourceId;
    const pair = pairMap?.get(pairId)?.displayName ?? pairId;
    return `${src} — ${pair}`;
  }
}

import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  inject,
  OnDestroy,
  OnInit,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Store } from '@ngrx/store';
import { Subscription as RxSubscription, combineLatest } from 'rxjs';
import { take, filter } from 'rxjs/operators';
import { MatButtonModule } from '@angular/material/button';
import { MatButtonToggleModule } from '@angular/material/button-toggle';
import { MatIconModule } from '@angular/material/icon';
import { MatChipsModule } from '@angular/material/chips';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatTooltipModule } from '@angular/material/tooltip';
import { MatSnackBar, MatSnackBarModule } from '@angular/material/snack-bar';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';
import {
  PriceChartComponent,
  PriceSeriesConfig,
  PricePoint,
  HorizontalLine,
  TradeMarker,
} from '../../shared/ui/price-chart/price-chart.component';
import { PageContainerComponent } from '../../shared/ui/page-container/page-container.component';
import { PageHeaderComponent } from '../../shared/ui/page-header/page-header.component';
import { ContentCardComponent } from '../../shared/ui/content-card/content-card.component';
import { LoadingStateComponent } from '../../shared/ui/loading-state/loading-state.component';
import { StatCardComponent } from '../../shared/ui/stat-card/stat-card.component';
import { PlaybackPlayerComponent } from '../../shared/ui/playback-player/playback-player.component';
import { ArbiConfigsFacade } from '../../features/arbi-configs/facades/arbi-configs.facade';
import { CatalogFacade } from '../../features/catalog/facades/catalog.facade';
import { DemoAccountFacade } from '../../features/demo-account/facades/demo-account.facade';
import {
  LiveChartSocketService,
  MultiLiveChartMessage,
} from '../../features/live-chart/services/live-chart-socket.service';
import { MultiPlaybackService, MultiPlaybackTick } from '../../features/arbi-configs/services/multi-playback.service';
import { AutoTradeEngine } from '../../features/arbi-configs/engine/auto-trade.engine';
import { selectAccessToken } from '../../features/auth/store/auth.selectors';
import {
  buildMultiChart,
  extractFieldKey,
  ChartSubscriptionInfo,
  MultiChartResult,
} from '../../shared/utils/multi-chart-builder';
import {
  ArbiConfig,
  Source,
  TradingPair,
  SwapDirection,
  DemoTrade,
  PlaybackState,
  PlaybackSpeed,
} from '../../shared/models';

const MAX_CHART_POINTS = 2000;

type PageMode = 'historical' | 'live' | 'playback';

@Component({
  selector: 'app-arbi-config-detail-page',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    FormsModule,
    RouterModule,
    MatButtonModule,
    MatButtonToggleModule,
    MatIconModule,
    MatChipsModule,
    MatFormFieldModule,
    MatInputModule,
    MatTooltipModule,
    MatSnackBarModule,
    MatSlideToggleModule,
    PriceChartComponent,
    PageContainerComponent,
    PageHeaderComponent,
    ContentCardComponent,
    LoadingStateComponent,
    StatCardComponent,
    PlaybackPlayerComponent,
  ],
  template: `
    <app-page-container>
      <app-page-header
        [title]="config?.name ?? 'Config'"
        subtitle="Arbitrage config detail — chart, trading & auto-trade">
        <div slot="actions" class="header-actions">
          <mat-button-toggle-group
            [value]="mode"
            (change)="onModeChange($event.value)"
            appearance="standard"
            class="mode-toggle">
            <mat-button-toggle value="historical">
              <mat-icon>history</mat-icon> Historical
            </mat-button-toggle>
            <mat-button-toggle value="playback">
              <mat-icon>play_circle</mat-icon> Playback
            </mat-button-toggle>
            <mat-button-toggle value="live">
              <mat-icon>wifi</mat-icon> Live
            </mat-button-toggle>
          </mat-button-toggle-group>

          <button mat-stroked-button [routerLink]="['/arbi-configs', configId, 'edit']">
            <mat-icon>edit</mat-icon> Edit
          </button>
          <button mat-stroked-button color="warn" (click)="onDelete()">
            <mat-icon>delete</mat-icon> Delete
          </button>
          <button mat-stroked-button routerLink="/arbi-configs">
            <mat-icon>arrow_back</mat-icon> Back
          </button>
        </div>
      </app-page-header>

      <!-- Config info cards -->
      <div class="info-row" *ngIf="config">
        <app-stat-card label="Trading" [value]="tradingLabel" icon="swap_horiz" color="purple" />
        <app-stat-card label="Profit Asset" [value]="config.profitAsset" icon="attach_money" color="green" />
        <app-stat-card label="Slippage" [value]="(config.slippage * 100 | number:'1.1-2') + '%'" icon="trending_flat" color="orange" />
        <app-stat-card label="Balance" [value]="(config.initialBalance | number:'1.0-2') ?? '0'" icon="account_balance" color="blue" />
      </div>

      <!-- Reference sources chips -->
      <app-content-card *ngIf="config" title="Reference Sources" [compact]="true">
        <div class="ref-chips">
          <span class="chip" *ngFor="let label of referenceLabels">{{ label }}</span>
        </div>
      </app-content-card>

      <!-- ── PLAYBACK MODE: Player Controls ── -->
      <ng-container *ngIf="mode === 'playback'">
        <app-content-card title="Playback Controls" [compact]="true">
          <div *ngIf="playbackState.loading" class="playback-loading">
            <mat-icon>hourglass_top</mat-icon> Loading historical data…
          </div>
          <div *ngIf="playbackState.error" class="error-msg">
            <mat-icon>error_outline</mat-icon>
            <span>{{ playbackState.error }}</span>
          </div>
          <app-playback-player
            *ngIf="!playbackState.loading && !playbackState.error && playbackState.totalPoints > 0"
            [state]="playbackState"
            (play)="onPlaybackPlay()"
            (pause)="onPlaybackPause()"
            (stop)="onPlaybackStop()"
            (speedChange)="onPlaybackSpeedChange($event)"
            (seek)="onPlaybackSeek($event)" />
        </app-content-card>
      </ng-container>

      <!-- Chart -->
      <app-loading-state *ngIf="loading" label="Loading price data…" />

      <div *ngIf="error" class="error-msg">
        <mat-icon>error_outline</mat-icon>
        <span>{{ error }}</span>
      </div>

      <app-content-card *ngIf="!loading && !error && series.length > 0" title="Price Chart">
        <ng-container slot="header-actions">
          <div class="live-badge" *ngIf="mode === 'live'">
            <span class="dot"></span> LIVE
          </div>
          <div class="live-badge live-badge--playback" *ngIf="mode === 'playback' && playbackState.isPlaying">
            <span class="dot"></span> PLAYBACK {{ playbackState.speed }}×
          </div>
          <button mat-icon-button
                  (click)="chartVisible = !chartVisible"
                  [matTooltip]="chartVisible ? 'Hide chart' : 'Show chart'">
            <mat-icon>{{ chartVisible ? 'expand_less' : 'expand_more' }}</mat-icon>
          </button>
        </ng-container>
        <app-price-chart
          *ngIf="chartVisible"
          [series]="series"
          [data]="chartData"
          [horizontalLines]="hLines"
          [tradeMarkers]="tradeMarkersList"
          [streaming]="false" />
      </app-content-card>

      <!-- ── TRADING SECTION (only in playback / live) ── -->
      <ng-container *ngIf="config && (mode === 'playback' || mode === 'live')">

        <!-- Balance cards -->
        <div class="info-row" style="margin-top: 16px;">
          <app-stat-card label="USDC Balance"
            [value]="(usdcBalance | number:'1.2-2') ?? '0.00'"
            icon="attach_money" color="green" />
          <app-stat-card label="WETH Balance"
            [value]="(wethBalance | number:'1.4-8') ?? '0.00000000'"
            icon="currency_exchange" color="purple" />
          <app-stat-card label="Portfolio (USDC)"
            [value]="(portfolioValue | number:'1.2-2') ?? '0.00'"
            icon="account_balance"
            [color]="pnl >= 0 ? 'green' : 'orange'" />
          <app-stat-card label="P&L"
            [value]="pnlDisplay"
            icon="trending_up"
            [color]="pnl >= 0 ? 'green' : 'orange'" />
        </div>

        <!-- Quote info -->
        <app-content-card *ngIf="tradingMid > 0" title="Trading Source Quote" [compact]="true">
          <div class="quote-info-row">
            <div class="quote-item quote-item--bid">
              <span class="quote-item__label">Bid</span>
              <span class="quote-item__value">{{ tradingBid | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item quote-item--ask">
              <span class="quote-item__label">Ask</span>
              <span class="quote-item__value">{{ tradingAsk | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item">
              <span class="quote-item__label">Mid</span>
              <span class="quote-item__value">{{ tradingMid | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item">
              <span class="quote-item__label">Avg Ref Mid</span>
              <span class="quote-item__value">{{ avgRefMid | number:'1.2-4' }}</span>
            </div>
            <div class="quote-item" *ngIf="engine?.hasPosition">
              <span class="quote-item__label">Peak</span>
              <span class="quote-item__value">{{ engine!.peakSellPrice | number:'1.2-4' }}</span>
            </div>
          </div>
        </app-content-card>

        <!-- Auto-trade toggle + Manual swap -->
        <app-content-card title="Trading" [elevated]="true">
          <div class="trading-header">
            <mat-slide-toggle [(ngModel)]="autoTradeEnabled" class="auto-toggle">
              Auto-Trade
            </mat-slide-toggle>
            <span class="auto-status" *ngIf="autoTradeEnabled && engine">
              {{ engine.hasPosition ? ' In Position' : '⏳ Waiting for signal' }}
            </span>
            <span class="auto-reason" *ngIf="lastAutoTradeReason">{{ lastAutoTradeReason }}</span>
          </div>

          <!-- Manual swap form -->
          <div class="swap-form" *ngIf="!autoTradeEnabled">
            <div class="swap-row">
              <mat-form-field appearance="outline" class="swap-field">
                <mat-label>{{ direction === 'USDC_TO_WETH' ? 'Spend USDC' : 'Spend WETH' }}</mat-label>
                <input matInput type="number" [(ngModel)]="amountIn" (ngModelChange)="recalcEstimate()"
                       min="0" [step]="direction === 'USDC_TO_WETH' ? 10 : 0.001" />
                <span matTextSuffix class="token-suffix">{{ direction === 'USDC_TO_WETH' ? 'USDC' : 'WETH' }}</span>
              </mat-form-field>

              <button mat-icon-button class="flip-btn" (click)="flipDirection()" matTooltip="Flip direction">
                <mat-icon>swap_vert</mat-icon>
              </button>

              <div class="estimate-box">
                <span class="estimate-label">You receive ≈</span>
                <span class="estimate-value">
                  {{ estimatedOut | number:(direction === 'USDC_TO_WETH' ? '1.4-8' : '1.2-4') }}
                  {{ direction === 'USDC_TO_WETH' ? 'WETH' : 'USDC' }}
                </span>
              </div>
            </div>

            <div class="action-row">
              <button mat-stroked-button (click)="setMax()">MAX</button>
              <button mat-flat-button color="primary" class="swap-btn"
                      [disabled]="!canSwap"
                      (click)="doSwap()">
                <mat-icon>swap_horiz</mat-icon>
                {{ direction === 'USDC_TO_WETH' ? 'Buy WETH' : 'Sell WETH' }}
              </button>
            </div>
          </div>
        </app-content-card>

        <!-- Trade History -->
        <app-content-card [title]="'Trade History (' + trades.length + ')'" *ngIf="trades.length > 0">
          <button slot="header-actions" mat-icon-button
                  (click)="showTradeHistory = !showTradeHistory"
                  [matTooltip]="showTradeHistory ? 'Hide table' : 'Show table'">
            <mat-icon>{{ showTradeHistory ? 'expand_less' : 'expand_more' }}</mat-icon>
          </button>
          <div class="trade-table-wrap" *ngIf="showTradeHistory">
            <table class="trade-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Step</th>
                  <th>Direction</th>
                  <th>Spent</th>
                  <th>Received</th>
                  <th>Price</th>
                  <th>Time</th>
                </tr>
              </thead>
              <tbody>
                <tr *ngFor="let t of trades">
                  <td>{{ t.id }}</td>
                  <td>{{ t.step != null ? t.step : '—' }}</td>
                  <td>
                    <span [class]="t.direction === 'USDC_TO_WETH' ? 'dir-buy' : 'dir-sell'">
                      {{ t.direction === 'USDC_TO_WETH' ? 'BUY' : 'SELL' }}
                    </span>
                  </td>
                  <td>{{ t.amountIn | number:(t.tokenIn === 'USDC' ? '1.2-2' : '1.4-8') }} {{ t.tokenIn }}</td>
                  <td>{{ t.amountOut | number:(t.tokenOut === 'USDC' ? '1.2-2' : '1.4-8') }} {{ t.tokenOut }}</td>
                  <td>{{ t.price | number:'1.2-4' }}</td>
                  <td>{{ (t.playbackTime ?? t.timestamp) | date:'HH:mm:ss' }}</td>
                </tr>
              </tbody>
            </table>
          </div>
        </app-content-card>

      </ng-container>
    </app-page-container>
  `,
  styles: [`
    @use 'styles/tokens' as t;

    .header-actions {
      display: flex;
      align-items: center;
      gap: 8px;
      flex-wrap: wrap;
    }

    .mode-toggle { margin-right: 8px; }

    .info-row {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
      gap: t.$spacing-sm;
      margin-bottom: t.$spacing-md;
    }

    .ref-chips { display: flex; flex-wrap: wrap; gap: 6px; }

    .chip {
      font-size: 12px;
      padding: 4px 12px;
      border-radius: 16px;
      background: var(--color-background);
      color: var(--color-text-secondary);
      border: 1px solid var(--color-border);
    }

    .error-msg {
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 16px;
      color: var(--color-danger, #ef4444);
      justify-content: center;
    }

    .playback-loading {
      display: flex;
      align-items: center;
      gap: 8px;
      color: var(--color-text-muted);
      padding: 8px 0;
    }


    .live-badge, .live-badge--playback {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 4px 10px;
      background: rgba(14, 203, 129, 0.15);
      border: 1px solid #0ecb81;
      border-radius: 4px;
      color: #0ecb81;
      font-size: 12px;
      font-weight: 600;
      letter-spacing: 1px;
      .dot {
        width: 8px; height: 8px; border-radius: 50%;
        background: currentColor;
        animation: pulse 1.5s ease-in-out infinite;
      }
    }
    .live-badge--playback {
      background: rgba(33, 150, 243, 0.15);
      border-color: #2196f3;
      color: #2196f3;
    }

    @keyframes pulse {
      0%, 100% { opacity: 1; }
      50%       { opacity: 0.2; }
    }

    app-content-card { display: block; margin-bottom: t.$spacing-md; }

    /* ── Quote info ── */
    .quote-info-row {
      display: flex;
      gap: t.$spacing-lg;
      flex-wrap: wrap;
      align-items: flex-end;
    }
    .quote-item {
      display: flex; flex-direction: column; gap: 2px;
      &__label {
        font-size: t.$font-size-xs;
        color: var(--color-text-muted);
        text-transform: uppercase;
        letter-spacing: 0.5px;
      }
      &__value {
        font-size: t.$font-size-lg;
        font-weight: t.$font-weight-bold;
        color: var(--color-text-primary);
      }
      &--bid .quote-item__value { color: #0ecb81; }
      &--ask .quote-item__value { color: #f6465d; }
    }

    /* ── Trading section ── */
    .trading-header {
      display: flex;
      align-items: center;
      gap: t.$spacing-md;
      margin-bottom: t.$spacing-md;
      flex-wrap: wrap;
    }
    .auto-toggle { font-weight: 600; }
    .auto-status {
      font-size: t.$font-size-sm;
      color: var(--color-text-secondary);
    }
    .auto-reason {
      font-size: t.$font-size-xs;
      color: var(--color-text-muted);
      font-style: italic;
    }

    .swap-form {
      display: flex;
      flex-direction: column;
      gap: t.$spacing-md;
    }
    .swap-row {
      display: flex;
      align-items: center;
      gap: t.$spacing-md;
      flex-wrap: wrap;
    }
    .swap-field { flex: 1; min-width: 200px; }
    .flip-btn {
      color: var(--color-text-secondary);
      transition: transform 0.3s ease;
      &:hover { transform: rotate(180deg); color: var(--color-text-primary); }
    }
    .estimate-box {
      flex: 1; min-width: 180px;
      display: flex; flex-direction: column;
      padding: t.$spacing-md;
      background: var(--color-background);
      border: 1px solid var(--color-border);
      border-radius: t.$radius-sm;
    }
    .estimate-label {
      font-size: t.$font-size-xs;
      color: var(--color-text-muted);
      margin-bottom: 4px;
    }
    .estimate-value {
      font-size: t.$font-size-lg;
      font-weight: t.$font-weight-bold;
      color: var(--color-text-primary);
    }
    .token-suffix {
      font-weight: t.$font-weight-semibold;
      color: var(--color-text-muted);
    }
    .action-row { display: flex; align-items: center; gap: t.$spacing-md; }
    .swap-btn {
      flex: 1; height: 48px;
      font-size: t.$font-size-base;
      font-weight: t.$font-weight-semibold;
    }

    /* Trade table */
    .trade-table-wrap { overflow-x: auto; }
    .trade-table {
      width: 100%; border-collapse: collapse; font-size: t.$font-size-sm;
      th, td {
        padding: 8px 12px; text-align: left;
        border-bottom: 1px solid var(--color-border);
        white-space: nowrap;
      }
      th {
        color: var(--color-text-muted);
        font-weight: t.$font-weight-semibold;
        font-size: t.$font-size-xs;
        text-transform: uppercase;
        letter-spacing: 0.5px;
      }
      td { color: var(--color-text-primary); }
    }
    .dir-buy { color: #0ecb81; font-weight: 600; }
    .dir-sell { color: #f6465d; font-weight: 600; }
  `],
})
export class ArbiConfigDetailPageComponent implements OnInit, OnDestroy {
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);
  private readonly store = inject(Store);
  private readonly configsFacade = inject(ArbiConfigsFacade);
  private readonly catalogFacade = inject(CatalogFacade);
  private readonly demoFacade = inject(DemoAccountFacade);
  private readonly liveChartSocket = inject(LiveChartSocketService);
  private readonly multiPlayback = inject(MultiPlaybackService);
  private readonly snackBar = inject(MatSnackBar);
  private readonly cdr = inject(ChangeDetectorRef);

  configId = '';
  config: ArbiConfig | null = null;
  mode: PageMode = 'historical';

  tradingLabel = '';
  referenceLabels: string[] = [];

  // Chart
  series: PriceSeriesConfig[] = [];
  chartData: PricePoint[] = [];
  hLines: HorizontalLine[] = [];
  loading = true;
  error = '';
  chartVisible = true;

  // Оригинальные исторические данные (для восстановления при переключении обратно)
  private historicalSeries: PriceSeriesConfig[] = [];
  private historicalChartData: PricePoint[] = [];

  // Playback
  playbackState: PlaybackState = {
    isPlaying: false, speed: 1, currentTime: 0, startTime: 0, endTime: 0,
    progress: 0, totalPoints: 0, currentIndex: 0, loading: false, error: '',
  };
  private allPlaybackPoints: PricePoint[] = [];

  // Trading prices
  tradingBid = 0;
  tradingAsk = 0;
  tradingMid = 0;
  avgRefMid = 0;

  // Demo account
  usdcBalance = 100;
  wethBalance = 0;
  initialUsdc = 100;
  portfolioValue = 100;
  pnl = 0;
  pnlDisplay = '+0.00 USDC';

  // Swap form
  direction: SwapDirection = 'USDC_TO_WETH';
  amountIn = 100;
  estimatedOut = 0;
  trades: DemoTrade[] = [];
  tradeMarkersList: TradeMarker[] = [];
  showTradeHistory = false;

  // Auto-trade
  autoTradeEnabled = false;
  engine: AutoTradeEngine | null = null;
  lastAutoTradeReason = '';

  // Актуальный step/time из последнего тика (не из state, т.к. state обновляется после батча)
  private lastTickIndex = 0;
  private lastTickTime = 0;

  private keyPrefixMap = new Map<string, string>();
  private allSubscriptionIds: string[] = [];
  private tradingSubId = '';
  private referenceSubIds: string[] = [];
  private liveValues = new Map<string, { bid: number; ask: number; mid: number }>();
  private chartSubs: ChartSubscriptionInfo[] = [];
  private rxSubs: RxSubscription[] = [];

  get canSwap(): boolean {
    if (this.amountIn <= 0 || this.tradingMid <= 0) return false;
    if (this.direction === 'USDC_TO_WETH') return this.amountIn <= this.usdcBalance;
    return this.amountIn <= this.wethBalance;
  }

  ngOnInit(): void {
    this.configId = this.route.snapshot.paramMap.get('id') ?? '';
    this.catalogFacade.loadAll();
    this.configsFacade.loadOne(this.configId);
    this.configsFacade.loadPrices(this.configId);

    // Wait for config + catalog to resolve labels
    const configSub = combineLatest([
      this.configsFacade.selectById(this.configId),
      this.catalogFacade.sources$,
      this.catalogFacade.pairs$,
    ]).pipe(
      filter(([c, sources]) => !!c && sources.length > 0),
    ).subscribe(([config, sources, pairs]) => {
      if (!config) return;
      this.config = config;

      const sourceMap = new Map(sources.map((s: Source) => [s.id, s]));
      const pairMap = new Map(pairs.map((p: TradingPair) => [p.id, p]));

      this.tradingLabel = this.makeLabel(config.tradingSourceId, config.tradingPairId, sourceMap, pairMap);
      this.referenceLabels = config.sources.map((s) =>
        this.makeLabel(s.sourceId, s.pairId, sourceMap, pairMap),
      );

      this.tradingSubId = config.tradingSubscriptionId;
      this.referenceSubIds = config.sources.map((s) => s.subscriptionId);

      // Init demo balance from config
      this.demoFacade.setInitialBalance(config.initialBalance);
      this.amountIn = config.initialBalance;

      // Init auto-trade engine
      this.engine = new AutoTradeEngine(config);

      this.cdr.markForCheck();
    });
    this.rxSubs.push(configSub);

    // Wait for prices (historical mode chart data)
    const pricesSub = combineLatest([
      this.configsFacade.currentPrices$,
      this.configsFacade.selectById(this.configId),
      this.catalogFacade.sources$,
      this.catalogFacade.pairs$,
    ]).pipe(
      filter(([prices, config, sources]) => !!prices && !!config && sources.length > 0),
      take(1),
    ).subscribe(([pricesResp, config, sources, pairs]) => {
      if (!pricesResp || !config) return;

      const sourceMap = new Map(sources.map((s: Source) => [s.id, s]));
      const pairMap = new Map(pairs.map((p: TradingPair) => [p.id, p]));

      this.chartSubs = [];
      this.chartSubs.push({
        id: config.tradingSubscriptionId,
        label: this.makeLabel(config.tradingSourceId, config.tradingPairId, sourceMap, pairMap),
        role: 'trading',
      });
      config.sources.forEach((s) => {
        this.chartSubs.push({
          id: s.subscriptionId,
          label: this.makeLabel(s.sourceId, s.pairId, sourceMap, pairMap),
          role: 'reference',
        });
      });

      const result: MultiChartResult = buildMultiChart(this.chartSubs, pricesResp.prices);
      this.series = result.series;
      this.chartData = result.data;
      this.keyPrefixMap = result.keyPrefixMap;
      this.allSubscriptionIds = this.chartSubs.map((s) => s.id);

      // Сохраняем оригинальные исторические данные для переключения обратно на historical
      this.historicalSeries = [...result.series];
      this.historicalChartData = [...result.data];

      this.loading = false;
      this.cdr.markForCheck();
    });
    this.rxSubs.push(pricesSub);

    // Handle price loading error
    const errSub = this.configsFacade.error$.pipe(
      filter((e) => !!e),
      take(1),
    ).subscribe((err) => {
      this.error = err ?? 'Failed to load data';
      this.loading = false;
      this.cdr.markForCheck();
    });
    this.rxSubs.push(errSub);

    // Subscribe to demo account state
    const demoSub = combineLatest([
      this.demoFacade.usdcBalance$,
      this.demoFacade.wethBalance$,
      this.demoFacade.initialUsdc$,
      this.demoFacade.tradeHistory$,
    ]).subscribe(([usdc, weth, initial, history]) => {
      this.usdcBalance = usdc;
      this.wethBalance = weth;
      this.initialUsdc = initial;
      this.trades = history;
      this.updateTradeMarkers();
      this.updatePortfolio();
      this.recalcEstimate();
      this.cdr.markForCheck();
    });
    this.rxSubs.push(demoSub);

    // Subscribe to playback state
    const pbStateSub = this.multiPlayback.state$.subscribe((s) => {
      this.playbackState = s;
      this.cdr.markForCheck();
    });
    this.rxSubs.push(pbStateSub);
  }

  ngOnDestroy(): void {
    this.rxSubs.forEach((s) => s.unsubscribe());
    this.liveChartSocket.disconnectAll();
    this.multiPlayback.stop();
  }

  /* ── Mode switching ── */

  onModeChange(newMode: string): void {
    const m = newMode as PageMode;
    if (m === this.mode) return;

    if (this.mode === 'live') {
      this.liveChartSocket.disconnectAll();
      this.liveValues.clear();
    }
    if (this.mode === 'playback') this.multiPlayback.stop();

    this.mode = m;

    if (m === 'live') {
      this.connectSockets();
    } else if (m === 'playback') {
      this.startPlaybackMode();
    } else if (m === 'historical') {
      // Восстанавливаем оригинальные исторические данные
      this.series = [...this.historicalSeries];
      this.chartData = [...this.historicalChartData];
      this.hLines = [];
    }
    this.cdr.markForCheck();
  }

  onDelete(): void {
    if (confirm('Are you sure you want to delete this config?')) {
      this.configsFacade.delete(this.configId);
    }
  }

  /* ── Playback controls ── */

  onPlaybackPlay(): void { this.multiPlayback.play(); }
  onPlaybackPause(): void { this.multiPlayback.pause(); }

  onPlaybackStop(): void {
    this.multiPlayback.stop();
    this.resetTradeState();
    this.startPlaybackMode();
  }

  onPlaybackSpeedChange(speed: PlaybackSpeed): void {
    this.multiPlayback.setSpeed(speed);
  }

  onPlaybackSeek(progress: number): void {
    this.multiPlayback.seekTo(progress);
    if (this.allPlaybackPoints.length > 0) {
      const idx = Math.min(
        Math.floor(progress * this.allPlaybackPoints.length),
        this.allPlaybackPoints.length - 1,
      );
      this.chartData = this.allPlaybackPoints.slice(0, idx + 1);
      this.cdr.markForCheck();
    }
  }

  /* ── Manual swap ── */

  flipDirection(): void {
    if (this.direction === 'USDC_TO_WETH') {
      this.direction = 'WETH_TO_USDC';
      this.amountIn = this.wethBalance;
    } else {
      this.direction = 'USDC_TO_WETH';
      this.amountIn = this.usdcBalance;
    }
    this.recalcEstimate();
  }

  setMax(): void {
    this.amountIn = this.direction === 'USDC_TO_WETH' ? this.usdcBalance : this.wethBalance;
    this.recalcEstimate();
  }

  recalcEstimate(): void {
    if (this.tradingMid <= 0 || this.amountIn <= 0) {
      this.estimatedOut = 0;
      return;
    }
    const slip = this.config?.slippage ?? 0.01;
    if (this.direction === 'USDC_TO_WETH') {
      const price = this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid;
      this.estimatedOut = this.amountIn / (price * (1 + slip));
    } else {
      const price = this.tradingBid > 0 ? this.tradingBid : this.tradingMid;
      this.estimatedOut = this.amountIn * (price * (1 - slip));
    }
  }

  doSwap(): void {
    if (!this.canSwap) return;
    const slip = this.config?.slippage ?? 0.01;
    const { step, playbackTime } = this.currentPlaybackInfo();
    // Покупка по ask, продажа по bid (как на реальном рынке)
    const execPrice = this.direction === 'USDC_TO_WETH'
      ? (this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid)
      : (this.tradingBid > 0 ? this.tradingBid : this.tradingMid);
    this.demoFacade.swap(this.direction, this.amountIn, slip, execPrice, step, playbackTime);
    this.snackBar.open(
      `Swap: ${this.amountIn.toFixed(2)} ${this.direction === 'USDC_TO_WETH' ? 'USDC → WETH' : 'WETH → USDC'}`,
      'OK', { duration: 3000 },
    );

    if (this.engine) {
      if (this.direction === 'USDC_TO_WETH') {
        this.engine.onBuy(this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid);
      } else {
        this.engine.onSell();
      }
    }
    this.updateHorizontalLines();
  }

  /* ── Playback Mode ── */

  private startPlaybackMode(): void {
    if (this.chartSubs.length === 0) return;

    // Используем данные из store — те же, что и для historical режима
    const sub = this.configsFacade.currentPrices$.pipe(
      filter((prices) => !!prices),
      take(1),
    ).subscribe((pricesResp) => {
      if (!pricesResp) return;

      const result = this.multiPlayback.loadFromData(this.chartSubs, pricesResp.prices);
      if (!result || result.data.length === 0) return;

      this.series = result.series;
      this.allPlaybackPoints = [...result.data];
      this.keyPrefixMap = result.keyPrefixMap;
      this.chartData = [];
      this.cdr.markForCheck();

      const tickSub = this.multiPlayback.tick$.subscribe((tick) => {
        this.onPlaybackTick(tick);
      });
      this.rxSubs.push(tickSub);
    });
    this.rxSubs.push(sub);
  }

  private onPlaybackTick(tick: MultiPlaybackTick): void {
    // Сохраняем актуальный step/time из тика (state обновляется после батча, а тик — для каждой точки)
    this.lastTickIndex = tick.index;
    this.lastTickTime = tick.time;

    // Only update chart data if chart is visible (major performance gain)
    if (this.chartVisible) {
      const targetLen = tick.index + 1;
      if (targetLen <= this.allPlaybackPoints.length && this.chartData.length < targetLen) {
        this.chartData = this.allPlaybackPoints.slice(0, targetLen);
      }
    }

    this.extractPricesFromTick(tick);
    this.runAutoTrade();
    this.updatePortfolio();
    this.updateHorizontalLines();
    this.cdr.markForCheck();
  }

  /* ── WebSocket (Live Mode) ── */

  private connectSockets(): void {
    if (this.allSubscriptionIds.length === 0) return;

    this.store
      .select(selectAccessToken)
      .pipe(take(1))
      .subscribe((token) => {
        if (!token) return;

        this.liveChartSocket.disconnectAll();
        const wsSub = this.liveChartSocket
          .connectMultiple(token, this.allSubscriptionIds)
          .subscribe({
            next: (msg) => this.onLivePriceUpdate(msg),
            error: (err) => console.error('ArbiConfig LiveChart WS error:', err),
          });
        this.rxSubs.push(wsSub);
      });
  }

  private onLivePriceUpdate(msg: MultiLiveChartMessage): void {
    const prefix = this.keyPrefixMap.get(msg.subscriptionId);
    if (!prefix) return;

    const fieldKey = extractFieldKey(msg.key);

    // Only update chart data if chart is visible
    if (this.chartVisible) {
      const newFieldKey = `${prefix}_${fieldKey}`;
      const last = this.chartData[this.chartData.length - 1];
      const newPoint: PricePoint = {
        ...(last ?? {}),
        time: msg.point.t,
        [newFieldKey]: msg.point.v,
      };
      let updated = [...this.chartData, newPoint];
      if (updated.length > MAX_CHART_POINTS) {
        updated = updated.slice(updated.length - MAX_CHART_POINTS);
      }
      this.chartData = updated;
    }

    // Update live values (always, for trading logic)
    const existing = this.liveValues.get(msg.subscriptionId) ?? { bid: 0, ask: 0, mid: 0 };
    const keyLower = fieldKey.toLowerCase();
    if (keyLower.includes('bid')) existing.bid = msg.point.v;
    else if (keyLower.includes('ask')) existing.ask = msg.point.v;
    else if (keyLower.includes('mid')) existing.mid = msg.point.v;
    if (existing.bid > 0 && existing.ask > 0 && existing.mid === 0) {
      existing.mid = (existing.bid + existing.ask) / 2;
    }
    this.liveValues.set(msg.subscriptionId, existing);

    this.derivePricesFromLive();
    this.runAutoTrade();
    this.updatePortfolio();
    this.updateHorizontalLines();
    this.cdr.markForCheck();
  }

  /* ── Price extraction ── */

  private extractPricesFromTick(tick: MultiPlaybackTick): void {
    const trading = tick.values.get(this.tradingSubId);
    if (trading) {
      this.tradingBid = trading.bid;
      this.tradingAsk = trading.ask;
      this.tradingMid = trading.mid;
    }

    let refSum = 0;
    let refCount = 0;
    for (const refId of this.referenceSubIds) {
      const ref = tick.values.get(refId);
      if (ref && ref.mid > 0) {
        refSum += ref.mid;
        refCount++;
      }
    }
    this.avgRefMid = refCount > 0 ? refSum / refCount : 0;
  }

  private derivePricesFromLive(): void {
    const trading = this.liveValues.get(this.tradingSubId);
    if (trading) {
      if (trading.bid > 0) this.tradingBid = trading.bid;
      if (trading.ask > 0) this.tradingAsk = trading.ask;
      if (trading.bid > 0 && trading.ask > 0) {
        this.tradingMid = (trading.bid + trading.ask) / 2;
      } else if (trading.mid > 0) {
        this.tradingMid = trading.mid;
      }
    }

    let refSum = 0;
    let refCount = 0;
    for (const refId of this.referenceSubIds) {
      const ref = this.liveValues.get(refId);
      if (ref) {
        const mid = ref.mid > 0 ? ref.mid : (ref.bid > 0 && ref.ask > 0 ? (ref.bid + ref.ask) / 2 : 0);
        if (mid > 0) { refSum += mid; refCount++; }
      }
    }
    this.avgRefMid = refCount > 0 ? refSum / refCount : 0;
  }

  /* ── Auto-Trade Engine ── */

  private runAutoTrade(): void {
    if (!this.autoTradeEnabled || !this.engine || !this.config) return;
    if (this.tradingBid <= 0 || this.tradingAsk <= 0 || this.avgRefMid <= 0) return;

    const result = this.engine.tick(this.tradingBid, this.tradingAsk, this.avgRefMid);

    if (result.action === 'buy') {
      const tradeAmountPct = this.config.tradeAmountPct ?? 100;
      const amount = this.usdcBalance * (tradeAmountPct / 100);
      if (amount > 0) {
        const { step, playbackTime } = this.currentPlaybackInfo();
        // Покупка по ask (как на реальном рынке)
        const buyPrice = this.tradingAsk > 0 ? this.tradingAsk : this.tradingMid;
        this.demoFacade.swap('USDC_TO_WETH', amount, this.config.slippage, buyPrice, step, playbackTime);
        this.engine.onBuy(this.tradingAsk);
        this.lastAutoTradeReason = result.reason ?? 'Auto-buy';
        this.snackBar.open(` Auto-BUY: ${amount.toFixed(2)} USDC`, 'OK', { duration: 3000 });
      }
    } else if (result.action === 'sell') {
      if (this.wethBalance > 0) {
        const { step, playbackTime } = this.currentPlaybackInfo();
        // Продажа по bid (как на реальном рынке)
        const sellPrice = this.tradingBid > 0 ? this.tradingBid : this.tradingMid;
        this.demoFacade.swap('WETH_TO_USDC', this.wethBalance, this.config.slippage, sellPrice, step, playbackTime);
        this.engine.onSell();
        this.lastAutoTradeReason = result.reason ?? 'Auto-sell';
        this.snackBar.open(` Auto-SELL: ${this.wethBalance.toFixed(8)} WETH`, 'OK', { duration: 3000 });
      }
    }
  }

  /* ── Horizontal Lines ── */

  private updateHorizontalLines(): void {
    const lines: HorizontalLine[] = [];

    if (this.engine && this.engine.hasPosition) {
      if (this.engine.buyPrice > 0) {
        lines.push({ value: this.engine.buyPrice, color: '#0ecb81', label: 'Buy Price' });
      }
      if (this.engine.trailingSellLevel > 0) {
        lines.push({ value: this.engine.trailingSellLevel, color: '#2196f3', label: 'Trailing TP' });
      }
      const slLevel = this.engine.stopLossLevel;
      if (slLevel > 0) {
        lines.push({ value: slLevel, color: '#f6465d', label: 'Stop Loss' });
      }
      if (this.engine.peakSellPrice > 0) {
        lines.push({ value: this.engine.peakSellPrice, color: '#ff9800', label: 'Peak', dash: true });
      }
    } else if (this.engine && !this.engine.hasPosition && this.avgRefMid > 0) {
      const autoBuyLevel = this.engine.getAutoBuyLevel(this.avgRefMid);
      if (autoBuyLevel > 0) {
        lines.push({ value: autoBuyLevel, color: '#ffeb3b', label: 'Auto-Buy Level' });
      }
    }

    this.hLines = lines;
  }

  /* ── Helpers ── */

  /** Возвращает текущий номер шага и время playback (если в playback-режиме) */
  private currentPlaybackInfo(): { step?: number; playbackTime?: number } {
    if (this.mode === 'playback') {
      return { step: this.lastTickIndex, playbackTime: this.lastTickTime };
    }
    return {};
  }

  private updateTradeMarkers(): void {
    this.tradeMarkersList = this.trades.map((t) => ({
      time: t.playbackTime ?? t.timestamp,
      price: t.price,
      direction: t.direction === 'USDC_TO_WETH' ? 'buy' as const : 'sell' as const,
      label: t.direction === 'USDC_TO_WETH' ? 'BUY' : 'SELL',
    }));
  }

  private updatePortfolio(): void {
    if (this.tradingMid > 0) {
      this.portfolioValue = this.usdcBalance + this.wethBalance * this.tradingMid;
    } else {
      this.portfolioValue = this.usdcBalance;
    }
    this.pnl = this.portfolioValue - this.initialUsdc;
    const sign = this.pnl >= 0 ? '+' : '';
    this.pnlDisplay = `${sign}${this.pnl.toFixed(2)} USDC`;
  }

  private resetTradeState(): void {
    this.demoFacade.setInitialBalance(this.config?.initialBalance ?? 100);
    this.engine?.reset();
    this.lastAutoTradeReason = '';
    this.tradingBid = 0;
    this.tradingAsk = 0;
    this.tradingMid = 0;
    this.avgRefMid = 0;
    this.hLines = [];
    this.direction = 'USDC_TO_WETH';
  }

  private makeLabel(
    sourceId?: string,
    pairId?: string,
    sourceMap?: Map<string, Source>,
    pairMap?: Map<string, TradingPair>,
  ): string {
    if (!sourceId || !pairId) return 'Unknown';
    const src = sourceMap?.get(sourceId)?.displayName ?? sourceId;
    const pair = pairMap?.get(pairId)?.displayName ?? pairId;
    return `${src} — ${pair}`;
  }
}

import {
  Component,
  Input,
  OnChanges,
  OnDestroy,
  OnInit,
  SimpleChanges,
} from '@angular/core';
import { AgCharts } from 'ag-charts-angular';
import { ModuleRegistry, AllCommunityModule } from 'ag-charts-community';
import { AllEnterpriseModule } from 'ag-charts-enterprise';
import type { AgCartesianChartOptions } from 'ag-charts-community';

ModuleRegistry.registerModules([AllCommunityModule, AllEnterpriseModule]);

/** Описание одной линии на графике */
export interface PriceSeriesConfig {
  /** Имя поля в объектах данных, например 'binanceBid' */
  key: string;
  /** Отображаемое название в легенде / тултипе, например 'Binance Bid' */
  name: string;
  /** Цвет линии, например '#0ecb81' */
  color: string;
}

/** Одна точка данных — `time` + произвольные ценовые поля, соответствующие PriceSeriesConfig.key */
export interface PricePoint {
  time: number;
  [key: string]: number;
}

/** Горизонтальная линия-аннотация на графике */
export interface HorizontalLine {
  /** Значение по оси Y */
  value: number;
  /** Цвет линии */
  color: string;
  /** Подпись */
  label: string;
  /** Пунктирная линия (по умолчанию true) */
  dash?: boolean;
}

/** Маркер сделки (покупка/продажа) на графике */
export interface TradeMarker {
  /** Timestamp сделки (ось X) */
  time: number;
  /** Цена сделки (ось Y) */
  price: number;
  /** Направление: buy или sell */
  direction: 'buy' | 'sell';
  /** Опциональная подпись */
  label?: string;
}

@Component({
  selector: 'app-price-chart',
  standalone: true,
  imports: [AgCharts],
  template: `
    <div class="price-chart-wrapper">
      <ag-charts [options]="options"></ag-charts>
    </div>
  `,
  styles: [`
    :host {
      display: block;
      width: 100%;
      height: 100%;
    }

    .price-chart-wrapper {
      width: 100%;
      height: 100%;
      min-height: 400px;
      background: #161a25;
      border-radius: 4px;
      overflow: hidden;

      ag-charts {
        display: block;
        width: 100%;
        height: 100%;
        min-height: 400px;
      }
    }
  `],
})
export class PriceChartComponent implements OnInit, OnChanges, OnDestroy {
  @Input() data: PricePoint[] = [];
  @Input() series: PriceSeriesConfig[] = [];
  @Input() hiddenKeys: string[] = [];
  @Input() streaming = false;
  @Input() horizontalLines: HorizontalLine[] = [];
  @Input() tradeMarkers: TradeMarker[] = [];

  options: AgCartesianChartOptions = {};

  private chartData: PricePoint[] = [];
  private streamIndex = 0;
  private intervalId: ReturnType<typeof setInterval> | null = null;
  /** Полный конфиг без данных — перестраивается только при изменении series/hiddenKeys/streaming/horizontalLines */
  private baseOptions: AgCartesianChartOptions = {};

  ngOnInit(): void {
    this.rebuildBaseOptions();
    this.initChart();
  }

  ngOnChanges(changes: SimpleChanges): void {
    const structureChanged =
      changes['series'] || changes['hiddenKeys'] || changes['streaming'] || changes['horizontalLines'];

    if (structureChanged) {
      this.rebuildBaseOptions();
      this.initChart();
    } else if (changes['data'] || changes['tradeMarkers']) {
      // Быстрый путь — изменились только данные, конфиг не перестраиваем
      if (this.streaming) {
        // В режиме стриминга initChart управляет собственным потоком; перезапускаем
        this.initChart();
      } else {
        this.chartData = [...this.data];
        this.applyData();
      }
    }
  }

  ngOnDestroy(): void {
    this.clearStreamInterval();
  }

  /* ── стриминг ── */

  private initChart(): void {
    this.clearStreamInterval();

    if (this.streaming && this.data.length > 0) {
      this.chartData = [];
      this.streamIndex = 0;
      this.applyData();
      this.intervalId = setInterval(() => this.tick(), 500);
    } else {
      this.chartData = [...this.data];
      this.applyData();
    }
  }

  private tick(): void {
    if (this.streamIndex < this.data.length) {
      this.chartData = [...this.chartData, this.data[this.streamIndex]];
      this.streamIndex++;
      this.applyData();
    } else {
      this.clearStreamInterval();
    }
  }

  private clearStreamInterval(): void {
    if (this.intervalId !== null) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  /* ── управление опциями ── */

  /**
   * Перестраивает всё КРОМЕ данных — серии, оси, легенду, зум, навигатор.
   * Вызывается только при изменении series / hiddenKeys / streaming.
   */
  private rebuildBaseOptions(): void {
    const hidden = new Set(this.hiddenKeys);
    const seriesDefs: any[] = this.series
      .filter((s) => !hidden.has(s.key))
      .map((s) => ({
        type: 'line' as const,
        xKey: 'time',
        yKey: s.key,
        yName: s.name,
        stroke: s.color,
        strokeWidth: 2,
        interpolation: { type: 'step' as const, position: 'end' as const },
        marker: { enabled: false },
        tooltip: {
          renderer: (params: any) => ({
            title: s.name,
            content: `${Number(params.datum[params.yKey]).toFixed(4)}`,
          }),
        },
      }));

    // Scatter-серии для маркеров покупок/продаж
    seriesDefs.push({
      type: 'scatter' as const,
      xKey: 'time',
      yKey: '_buyPrice',
      yName: ' Buy',
      marker: {
        shape: 'triangle',
        size: 14,
        fill: '#0ecb81',
        stroke: '#fff',
        strokeWidth: 1.5,
      },
      tooltip: {
        renderer: (params: any) => ({
          title: ' Buy',
          content: `Price: ${Number(params.datum._buyPrice).toFixed(4)}`,
        }),
      },
    });
    seriesDefs.push({
      type: 'scatter' as const,
      xKey: 'time',
      yKey: '_sellPrice',
      yName: ' Sell',
      marker: {
        shape: 'diamond',
        size: 14,
        fill: '#f6465d',
        stroke: '#fff',
        strokeWidth: 1.5,
      },
      tooltip: {
        renderer: (params: any) => ({
          title: ' Sell',
          content: `Price: ${Number(params.datum._sellPrice).toFixed(4)}`,
        }),
      },
    });

    this.baseOptions = {
      background: { fill: '#161a25' },
      padding: { top: 16, right: 16, bottom: 16, left: 16 },
      height: 500,
      series: seriesDefs,
      axes: {
        x: {
          type: 'number',
          position: 'bottom',
          label: {
            color: '#848e9c',
            formatter: (params: any) => {
              const d = new Date(params.value);
              return `${d.getHours().toString().padStart(2, '0')}:${d
                .getMinutes()
                .toString()
                .padStart(2, '0')}:${d.getSeconds().toString().padStart(2, '0')}`;
            },
          },
          gridLine: { style: [{ stroke: '#2b3139', lineDash: [4, 4] }] },
          line: { stroke: '#2b3139' },
          crosshair: { enabled: true, stroke: '#848e9c', lineDash: [4, 4] },
        },
        y: {
          type: 'number',
          position: 'right',
          label: { color: '#848e9c' },
          gridLine: { style: [{ stroke: '#2b3139', lineDash: [4, 4] }] },
          line: { stroke: '#2b3139' },
          crosshair: { enabled: true, stroke: '#848e9c', lineDash: [4, 4] },
          crossLines: this.horizontalLines
            .filter((hl) => hl.value > 0)
            .map((hl) => ({
              type: 'line' as const,
              value: hl.value,
              stroke: hl.color,
              strokeWidth: 1.5,
              lineDash: hl.dash !== false ? [6, 4] : undefined,
              label: {
                text: `${hl.label}: ${hl.value.toFixed(2)}`,
                position: 'right' as const,
                color: hl.color,
                fontSize: 10,
              },
            })),
        },
      },
      legend: {
        position: 'top',
        item: { label: { color: '#eaecef' } },
      },
      zoom: {
        enabled: true,
        axes: 'x',
        scrollingStep: 0.3,
      },
      navigator: {
        enabled: true,
        height: 30,
      },
    };
  }

  /**
   * Лёгкое обновление — только подменяет данные в существующем конфиге.
   * Создаёт новую ссылку на options, чтобы ag-charts подхватил изменение.
   * Если есть tradeMarkers, инжектит их как _buyPrice / _sellPrice в данные.
   */
  private applyData(): void {
    let data = [...this.chartData];

    if (this.tradeMarkers.length > 0) {
      // Строим Map time → PricePoint для быстрого поиска
      const timeMap = new Map<number, PricePoint>();
      for (const pt of data) {
        timeMap.set(pt.time, pt);
      }

      for (const m of this.tradeMarkers) {
        const key = m.direction === 'buy' ? '_buyPrice' : '_sellPrice';
        const existing = timeMap.get(m.time);
        if (existing) {
          // Точка с таким time уже есть — добавляем маркер
          (existing as any)[key] = m.price;
        } else {
          // Нет точки — ищем ближайшую или добавляем новую
          const closestPt = this.findClosest(data, m.time);
          if (closestPt && Math.abs(closestPt.time - m.time) < 60_000) {
            (closestPt as any)[key] = m.price;
          } else {
            // Вставляем отдельную точку
            data.push({ time: m.time, [key]: m.price } as any);
          }
        }
      }

      // Сортируем по time если добавили новые точки
      data.sort((a, b) => a.time - b.time);
    }

    this.options = { ...this.baseOptions, data };
  }

  /** Находит ближайшую точку по time (бинарный поиск) */
  private findClosest(data: PricePoint[], time: number): PricePoint | null {
    if (data.length === 0) return null;
    let lo = 0;
    let hi = data.length - 1;
    while (lo < hi) {
      const mid = (lo + hi) >> 1;
      if (data[mid].time < time) lo = mid + 1;
      else hi = mid;
    }
    // Проверяем lo и lo-1
    if (lo > 0 && Math.abs(data[lo - 1].time - time) < Math.abs(data[lo].time - time)) {
      return data[lo - 1];
    }
    return data[lo];
  }
}

import {
  Component,
  Input,
  OnChanges,
  OnDestroy,
  OnInit,
  SimpleChanges,
} from '@angular/core';
import { AgCharts } from 'ag-charts-angular';
import { ModuleRegistry, AllCommunityModule } from 'ag-charts-community';
import { AllEnterpriseModule } from 'ag-charts-enterprise';
import type { AgCartesianChartOptions } from 'ag-charts-community';

ModuleRegistry.registerModules([AllCommunityModule, AllEnterpriseModule]);

/** Описание одной линии на графике */
export interface PriceSeriesConfig {
  /** Имя поля в объектах данных, например 'binanceBid' */
  key: string;
  /** Отображаемое название в легенде / тултипе, например 'Binance Bid' */
  name: string;
  /** Цвет линии, например '#0ecb81' */
  color: string;
}

/** Одна точка данных — `time` + произвольные ценовые поля, соответствующие PriceSeriesConfig.key */
export interface PricePoint {
  time: number;
  [key: string]: number;
}

/** Горизонтальная линия-аннотация на графике */
export interface HorizontalLine {
  /** Значение по оси Y */
  value: number;
  /** Цвет линии */
  color: string;
  /** Подпись */
  label: string;
  /** Пунктирная линия (по умолчанию true) */
  dash?: boolean;
}

/** Маркер сделки (покупка/продажа) на графике */
export interface TradeMarker {
  /** Timestamp сделки (ось X) */
  time: number;
  /** Цена сделки (ось Y) */
  price: number;
  /** Направление: buy или sell */
  direction: 'buy' | 'sell';
  /** Опциональная подпись */
  label?: string;
}

@Component({
  selector: 'app-price-chart',
  standalone: true,
  imports: [AgCharts],
  template: `
    <div class="price-chart-wrapper">
      <ag-charts [options]="options"></ag-charts>
    </div>
  `,
  styles: [`
    :host {
      display: block;
      width: 100%;
      height: 100%;
    }

    .price-chart-wrapper {
      width: 100%;
      height: 100%;
      min-height: 400px;
      background: #161a25;
      border-radius: 4px;
      overflow: hidden;

      ag-charts {
        display: block;
        width: 100%;
        height: 100%;
        min-height: 400px;
      }
    }
  `],
})
export class PriceChartComponent implements OnInit, OnChanges, OnDestroy {
  @Input() data: PricePoint[] = [];
  @Input() series: PriceSeriesConfig[] = [];
  @Input() hiddenKeys: string[] = [];
  @Input() streaming = false;
  @Input() horizontalLines: HorizontalLine[] = [];
  @Input() tradeMarkers: TradeMarker[] = [];

  options: AgCartesianChartOptions = {};

  private chartData: PricePoint[] = [];
  private streamIndex = 0;
  private intervalId: ReturnType<typeof setInterval> | null = null;
  /** Полный конфиг без данных — перестраивается только при изменении series/hiddenKeys/streaming/horizontalLines */
  private baseOptions: AgCartesianChartOptions = {};

  ngOnInit(): void {
    this.rebuildBaseOptions();
    this.initChart();
  }

  ngOnChanges(changes: SimpleChanges): void {
    const structureChanged =
      changes['series'] || changes['hiddenKeys'] || changes['streaming'] || changes['horizontalLines'];

    if (structureChanged) {
      this.rebuildBaseOptions();
      this.initChart();
    } else if (changes['data'] || changes['tradeMarkers']) {
      // Быстрый путь — изменились только данные, конфиг не перестраиваем
      if (this.streaming) {
        // В режиме стриминга initChart управляет собственным потоком; перезапускаем
        this.initChart();
      } else {
        this.chartData = [...this.data];
        this.applyData();
      }
    }
  }

  ngOnDestroy(): void {
    this.clearStreamInterval();
  }

  /* ── стриминг ── */

  private initChart(): void {
    this.clearStreamInterval();

    if (this.streaming && this.data.length > 0) {
      this.chartData = [];
      this.streamIndex = 0;
      this.applyData();
      this.intervalId = setInterval(() => this.tick(), 500);
    } else {
      this.chartData = [...this.data];
      this.applyData();
    }
  }

  private tick(): void {
    if (this.streamIndex < this.data.length) {
      this.chartData = [...this.chartData, this.data[this.streamIndex]];
      this.streamIndex++;
      this.applyData();
    } else {
      this.clearStreamInterval();
    }
  }

  private clearStreamInterval(): void {
    if (this.intervalId !== null) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  /* ── управление опциями ── */

  /**
   * Перестраивает всё КРОМЕ данных — серии, оси, легенду, зум, навигатор.
   * Вызывается только при изменении series / hiddenKeys / streaming.
   */
  private rebuildBaseOptions(): void {
    const hidden = new Set(this.hiddenKeys);
    const seriesDefs: any[] = this.series
      .filter((s) => !hidden.has(s.key))
      .map((s) => ({
        type: 'line' as const,
        xKey: 'time',
        yKey: s.key,
        yName: s.name,
        stroke: s.color,
        strokeWidth: 2,
        interpolation: { type: 'step' as const, position: 'end' as const },
        marker: { enabled: false },
        tooltip: {
          renderer: (params: any) => ({
            title: s.name,
            content: `${Number(params.datum[params.yKey]).toFixed(4)}`,
          }),
        },
      }));

    // Scatter-серии для маркеров НЕ добавляем в baseOptions —
    // они добавляются динамически в applyData() с собственным массивом data

    this.baseOptions = {
      background: { fill: '#161a25' },
      padding: { top: 16, right: 16, bottom: 16, left: 16 },
      height: 500,
      series: seriesDefs,
      axes: {
        x: {
          type: 'number',
          position: 'bottom',
          label: {
            color: '#848e9c',
            formatter: (params: any) => {
              const d = new Date(params.value);
              return `${d.getHours().toString().padStart(2, '0')}:${d
                .getMinutes()
                .toString()
                .padStart(2, '0')}:${d.getSeconds().toString().padStart(2, '0')}`;
            },
          },
          gridLine: { style: [{ stroke: '#2b3139', lineDash: [4, 4] }] },
          line: { stroke: '#2b3139' },
          crosshair: { enabled: true, stroke: '#848e9c', lineDash: [4, 4] },
        },
        y: {
          type: 'number',
          position: 'right',
          label: { color: '#848e9c' },
          gridLine: { style: [{ stroke: '#2b3139', lineDash: [4, 4] }] },
          line: { stroke: '#2b3139' },
          crosshair: { enabled: true, stroke: '#848e9c', lineDash: [4, 4] },
          crossLines: this.horizontalLines
            .filter((hl) => hl.value > 0)
            .map((hl) => ({
              type: 'line' as const,
              value: hl.value,
              stroke: hl.color,
              strokeWidth: 1.5,
              lineDash: hl.dash !== false ? [6, 4] : undefined,
              label: {
                text: `${hl.label}: ${hl.value.toFixed(2)}`,
                position: 'right' as const,
                color: hl.color,
                fontSize: 10,
              },
            })),
        },
      },
      legend: {
        position: 'top',
        item: { label: { color: '#eaecef' } },
      },
      zoom: {
        enabled: true,
        axes: 'x',
        scrollingStep: 0.3,
      },
      navigator: {
        enabled: true,
        height: 30,
      },
    };
  }

  /**
   * Лёгкое обновление — подменяет данные в существующем конфиге.
   * Если есть tradeMarkers, добавляет scatter-серии с собственными массивами data
   * (не инжектирует в основные данные — это предотвращает stack overflow в AG Charts).
   */
  private applyData(): void {
    const data = [...this.chartData];

    // Собираем серии: начинаем с базовых (line), затем добавляем scatter если есть маркеры
    const seriesDefs: any[] = [...(this.baseOptions.series ?? [])];

    if (this.tradeMarkers.length > 0) {
      const buyData = this.tradeMarkers
        .filter((m) => m.direction === 'buy')
        .map((m) => ({ time: m.time, price: m.price }));
      const sellData = this.tradeMarkers
        .filter((m) => m.direction === 'sell')
        .map((m) => ({ time: m.time, price: m.price }));

      if (buyData.length > 0) {
        seriesDefs.push({
          type: 'scatter' as const,
          xKey: 'time',
          yKey: 'price',
          yName: ' Buy',
          data: buyData,
          marker: {
            shape: 'triangle',
            size: 14,
            fill: '#0ecb81',
            stroke: '#fff',
            strokeWidth: 1.5,
          },
          tooltip: {
            renderer: (params: any) => ({
              title: ' Buy',
              content: `Price: ${Number(params.datum.price).toFixed(4)}`,
            }),
          },
        });
      }

      if (sellData.length > 0) {
        seriesDefs.push({
          type: 'scatter' as const,
          xKey: 'time',
          yKey: 'price',
          yName: ' Sell',
          data: sellData,
          marker: {
            shape: 'diamond',
            size: 14,
            fill: '#f6465d',
            stroke: '#fff',
            strokeWidth: 1.5,
          },
          tooltip: {
            renderer: (params: any) => ({
              title: ' Sell',
              content: `Price: ${Number(params.datum.price).toFixed(4)}`,
            }),
          },
        });
      }
    }

    this.options = { ...this.baseOptions, series: seriesDefs, data };
  }
}
